	@Override
	protected CubeVector prepareFilterConditionsForLOV(String strSearchText, String columnName, IDataObject cubeInfo,
			UserInfo userInfo, Map filterConditionMap, boolean showAllData, boolean isCustomSort,
			boolean isSkipcubedatasetcolumndataaccesspermission, String filterCondition)  throws CubeException, ALSException {

		CubeVector combinedCon = null;
		CubeVector condList = new CubeVector();

		if (strSearchText != null && !strSearchText.equals("")) {
			CubeConditionInfo cubeCondition = new CubeConditionInfo(CubeConditionInfo.AND, columnName,
					CubeConditionInfo.STARTS_WITH, strSearchText);
			cubeCondition.setCaseSensitive(false);
			cubeCondition.setDisplayFormat(strSearchText);
			condList.add(cubeCondition);
 			cubeCondition = null;
		}
		if (filterCondition != null && !filterCondition.equals("")) {
			String[] multipleCondition = filterCondition.split("#\\|\\|#");
			
			for(int i = 0; i < multipleCondition.length ; i++) {
				String singleCondition = multipleCondition[i];
				
				if (singleCondition != null && !singleCondition.equals("")) {
					CubeConditionInfo cubeCondition = new CubeConditionInfo(CubeConditionInfo.AND, singleCondition.split("=")[0],
							CubeConditionInfo.EQ, singleCondition.split("=")[1]);
					cubeCondition.setCaseSensitive(false);
					cubeCondition.setDisplayFormat(singleCondition.split("=")[1]);
					condList.add(cubeCondition);
					cubeCondition = null;
				}
			}
		}
		// For retrieval parameter
		if (!showAllData && false) {
			CubeVector preloadedParList = getPreloadingParameterListFromOrgCube();
			if (preloadedParList.size() != 0)
				combinedCon = (CubeVector) CubeUtil.addConditions(preloadedParList, condList, false);
			else
				combinedCon = condList;
		} else {
			combinedCon = condList;
		}
		combinedCon = (CubeVector) CubeUtil.addConditions(combinedCon,
				dataAccessRightsServiceUtil.getDataAccessRightsConditions(cubeInfo, userInfo), false);

		// For filter conditions

		Vector vDimension = null;
		CubeVector cvCondition2 = new CubeVector();
		Object[] keys = filterConditionMap.keySet().toArray();
		if (keys.length > 0)
			vDimension = cubeMetadataServiceUtil.getDimensionColumns(cubeInfo, userInfo,
					isSkipcubedatasetcolumndataaccesspermission);

		for (int k = 0; k < keys.length; k++) {
			if (null != vDimension && vDimension.contains(keys[k].toString())) {
				if (!isCustomSort) {
					if (keys[k].toString().equals(columnName)) {
						continue;
					}
				}
				CubeVector cvCond = (CubeVector)filterConditionMap.get(keys[k].toString());
    			CubeVector cvCondition = new CubeVector();
    			//solving bug number 13328(multi dependent) add new if condition.
    			if(cvCond != null && !cvCond.isEmpty()) {
    				for(int i = 0; i<cvCond.size(); i++){
    					CubeConditionInfo cond1 = new CubeConditionInfo();
    					cond1 = (CubeConditionInfo) cvCond.get(i);
    					CubeConditionInfo cond = new CubeConditionInfo(cond1.getLogicalOperator(),cond1.getColumnName(),cond1.getConditionalOperator(),cond1.getConditionalValue(),cond1.getGroupId(),cond1.getRangeType(),cond1.getCriteriaType(), cond1.getCriteriaTypeTo(), cond1.getTimeSeriesYearType(), cond1.getTimeSeriesTimeType(), cond1.getxValue(), cond1.getxValueTo(), cond1.isSkipEmptyPeriod(), cond1.isIncludeCurrentDay(), cond1.getStrTimeSeriesValue(), cond1.getGroupIdNew(), cond1.getSequence());
    					Object contionObject = cond.getConditionalValue();
    					if(contionObject instanceof DateObject) {
    						DateObject dt1 = new DateObject();
    						dt1 = (DateObject) cond.getConditionalValue();
    						DateObject dt = new DateObject(dt1.isFinancialYear(),dt1.getFirstMonthOfYear(),dt1.getValueType(),dt1.getValue(),dt1.getToRange(),false,dt1.getRangeType(),dt1.isAggregatePeriod(),dt1.getTimeseriesondate(),dt1.getRealtimetoday());
    						if(!(dt.getValueType().equals("ytd") || dt.getValueType().equals("htd") || dt.getValueType().equals("qtd") || dt.getValueType().equals("mtd") || dt.getValueType().equals("wtd"))){
    							cvCondition.add(cond);
    						} 
    						cond.setConditionalValue(dt);
    					} else {
    						cvCondition.add(cond);
    					}
    				}
    			}
				if (cvCondition != null && cvCondition.size() > 0)
					cvCondition2 = (CubeVector) CubeUtil.addConditions(cvCondition2, (CubeVector) cvCondition.clone(),
							false);
			}
		}

		for (int i = 0; cvCondition2 != null && i < cvCondition2.size(); i++) {
			combinedCon.add(cvCondition2.elementAt(i));
		}

		return combinedCon;
	}

	@Override
	public List<SelectItem> getDataDisplayValueMappingOnLOV(HashtableEx ddvmMap, List<Object> cubeDataValueList,
			String userId, int itemType, String strColumnName) {

		List<SelectItem> lovDataList = new ArrayList<SelectItem>();
		String displayFormat = userManagementServiceUtil.getUserDateDisplayFormat(userId, itemType);

		// For applying display format and ddvm value
		ALSCalendarFormat alsCalendarFmt = null;
		boolean bFormatting = (displayFormat != null && !"".equals(displayFormat));
		if (bFormatting)
			alsCalendarFmt = new ALSCalendarFormat(displayFormat);

		Object dataObj = null;

		if (cubeDataValueList instanceof CubeVector<?>
				|| (cubeDataValueList instanceof List<?> && (!cubeDataValueList.isEmpty() && !(cubeDataValueList.get(0) instanceof SelectItem)))) {
			for (int i = 0; i < cubeDataValueList.size(); i++) {
				SelectItem item = new SelectItem();
				dataObj = cubeDataValueList.get(i);
				if (dataObj instanceof SelectItem) {
					item = (SelectItem) cubeDataValueList.get(i);
				} else {
					if (bFormatting && dataObj != null) {
						// item.setValue(dataObj.toString()); solving bug number 9490
						item.setValue(dataObj.toString()); // solving bug number 11224
						if (dataObj instanceof Date) {
							item.setLabel(alsCalendarFmt.format((java.util.Date) dataObj));
							// item.setValue(alsCalendarFmt.format((java.util.Date)dataObj));
						} /*
							 * else { item.setValue(dataObj.toString()); }
							 */
					} else if (dataObj == null) { // changed the location to first check if the data is null - By
													// Preethi (03-12-2015)
						item.setValue(AppConstants.NULL_DISPLAY_VALUE);
						dataObj = AppConstants.NULL_DISPLAY_VALUE;
					} else {
						item.setValue(dataObj.toString());
						item.setLabel(dataObj.toString());
					}
				
					if (ddvmMap != null && ddvmMap.size() > 0) {

						if (ddvmMap.containsKey(strColumnName)) {
							Vector packDisplayList = (Vector) ddvmMap.get(strColumnName);

							if (packDisplayList != null && packDisplayList.size() > 0) {
								for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
									String[] values = (String[]) iterator.next();
									if (values[0].equalsIgnoreCase(dataObj + "")) {
										item.setLabel(dataObj + " [ " + values[1] + " ]");
										item.setValue(dataObj.toString());
										//break;
									} 
									/*else {
										item.setValue(dataObj.toString());
										item.setLabel(dataObj.toString());
									}*/
								}
							}
						} else {
							if (ddvmMap.containsKey(dataObj + "")) {
								item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj + "") + " ]");
								item.setValue(dataObj.toString());
							} /*
								 * else { item.setValue(dataObj.toString()); item.setLabel(dataObj.toString());
								 * }
								 */
							if (item.getLabel() == null) {
								item.setLabel(dataObj.toString());
							}
						}
					} else {
						if ("NULL".equals(item.getValue())) {
							item.setLabel(AppConstants.NULL_DISPLAY_VALUE);
						} else if (!bFormatting) {
							item.setLabel(item.getValue());
						} else {
							if (item.getValue().equals(AppConstants.NULL_DISPLAY_VALUE)) {
								item.setLabel(AppConstants.NULL_DISPLAY_VALUE);
							}

							if (item.getLabel() == null) {
								item.setLabel(dataObj.toString());
							}
						}
					}
				}
				lovDataList.add(item);
			}
		} else {

			for (int i = 0; i < cubeDataValueList.size(); i++) {
				SelectItem item = (SelectItem) cubeDataValueList.get(i);
				dataObj = item.getLabel();

				if (ddvmMap != null && ddvmMap.size() > 0) {

					if (ddvmMap.containsKey(strColumnName)) {
						Vector packDisplayList = (Vector) ddvmMap.get(strColumnName);

						if (packDisplayList != null && packDisplayList.size() > 0) {
							for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
								String[] values = (String[]) iterator.next();
								if (values[0].equalsIgnoreCase((String) dataObj)) {
									item.setLabel(dataObj + " [ " + values[1] + " ]");
									//break;
								} 
								/*else {
									item.setLabel(dataObj.toString());
								}*/
							}
						}
					} else {
						if (ddvmMap.containsKey(dataObj + "")) {
							item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj + "") + " ]");
						}
					}
				}

				lovDataList.add(item);
			}

		}

		return lovDataList;
	}

	@Override
	protected List<SelectItem> getUDHCItemsForLOV(String columnName, String strSearchText,
			List<Object> cubeDataValueList, Vector<CubeDataLabel> vUDHCList, HashtableEx ddvmMap) {

		Vector<CubeDataLabel> vUDLabel = new Vector<CubeDataLabel>();
		List<SelectItem> lovDataList = new ArrayList<SelectItem>();

		for (int i = 0; i < vUDHCList.size(); i++) {
			CubeDataLabel labelUDHC = (CubeDataLabel) (vUDHCList.elementAt(i));
			if (labelUDHC.getColumnName().equalsIgnoreCase(columnName)
					&& labelUDHC.getLabelText().toUpperCase().contains(strSearchText.toUpperCase())) {
				vUDLabel.addElement(labelUDHC);
			}
		}

		if (vUDLabel.size() != 0) {
			Object dataObj = null;

			for (int j = 0; j < vUDLabel.size(); j++) {
				dataObj = vUDLabel.elementAt(j);

				if (!cubeDataValueList.contains(dataObj)) {
					SelectItem item = new SelectItem();

					if (ddvmMap != null && ddvmMap.containsKey(columnName)) {
						Vector packDisplayList = (Vector) ddvmMap.get(columnName);
						if (packDisplayList != null && packDisplayList.size() > 0) {
							for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
								String[] values = (String[]) iterator.next();
								if (values[0].equalsIgnoreCase(dataObj.toString())) {
									item.setLabel(dataObj + " [ " + values[1] + " ]");
									item.setValue(dataObj.toString());
									break;
								} else {
									item.setValue(dataObj.toString());
									item.setLabel(dataObj.toString());
								}
							}
						}
					} else {
						if (ddvmMap != null && ddvmMap.size() > 0) {
							if (ddvmMap.containsKey(dataObj.toString())) {
								item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj.toString()) + " ]");
								item.setValue(dataObj.toString());
							} else {
								item.setValue(dataObj.toString());
								item.setLabel(dataObj.toString());
							}
						} else {
							item.setValue(dataObj.toString());
							item.setLabel(dataObj.toString());
						}
					}

					lovDataList.add(item);
				}
			}
		}

		return lovDataList;
	}

	@Override
	protected List<SelectItem> getGlobalVariableForLOV(String columnName, String strSearchText,
			List<Object> cubeDataValueList, List<ActiveGlobalVariableInfo> activeGlobalVariableInfoList,
			boolean isMeasure) {

		List<SelectItem> lovDataList = new ArrayList<SelectItem>();

		if (activeGlobalVariableInfoList != null && activeGlobalVariableInfoList.size() > 0) {
			try {
				int columnType = CubeUtil.getColumnType(columnName, this.getOriginalResultSetMetaData());
				for (int i = 0; i < activeGlobalVariableInfoList.size(); i++) {
					ActiveGlobalVariableInfo activeGlobalVariableInfo = activeGlobalVariableInfoList.get(i);
					GlobalVariableInfo globalVariableInfo = activeGlobalVariableInfo.getGlobalVariableInfo();
					String variableName = globalVariableInfo.getAssociatedColumnName();
					String type = globalVariableInfo.getType();
					String globalVariableName = globalVariableInfo.getGlobalVariableName().substring(1,
							globalVariableInfo.getGlobalVariableName().lastIndexOf("$"));
					if (!strSearchText.equals("")
							&& !globalVariableName.toLowerCase().contains(strSearchText.toLowerCase()))
						continue;
					if (!isMeasure) {
						if (type.equals(String.valueOf(columnType))) {
							SelectItem item = new SelectItem();
							item.setLabel(globalVariableName);
							item.setValue(globalVariableInfo.getGlobalVariableName());
							lovDataList.add(item);
						} else {
							if (type.equals(String.valueOf(Types.DOUBLE))) {
								if (columnType == Types.DECIMAL || columnType == Types.NUMERIC
										|| columnType == Types.FLOAT || columnType == Types.REAL) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							} else if (type.equals(String.valueOf(Types.BOOLEAN))) {
								if (columnType == Types.BIT) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							}
							// modified by harsh on 12 Jan 2016
							if (type.equals(String.valueOf(Types.DATE)) || type.equals(String.valueOf(Types.TIME))
									|| type.equals(String.valueOf(Types.TIMESTAMP))) {
								if (columnType == Types.DATE || columnType == Types.TIME
										|| columnType == Types.TIMESTAMP) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}

							}
						}
					} else {

						if (type.equals(String.valueOf(columnType))) {
							SelectItem item = new SelectItem();
							item.setLabel(globalVariableName);
							item.setValue(globalVariableInfo.getGlobalVariableName());
							lovDataList.add(item);
						} else {
							if ((type.equals(String.valueOf(Types.DOUBLE))
									|| type.equals(String.valueOf(Types.INTEGER)))
									&& (columnType == Types.DECIMAL || columnType == Types.NUMERIC
											|| columnType == Types.FLOAT || columnType == Types.REAL
											|| columnType == Types.INTEGER || columnType == Types.DOUBLE)) {
								SelectItem item = new SelectItem();
								item.setLabel(globalVariableName);
								item.setValue(globalVariableInfo.getGlobalVariableName());
								lovDataList.add(item);
							} else if (type.equals(String.valueOf(Types.BOOLEAN))) {
								if (columnType == Types.BIT) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							}
							// modified by harsh on 12 Jan 2016
							if (type.equals(String.valueOf(Types.DATE)) || type.equals(String.valueOf(Types.TIME))
									|| type.equals(String.valueOf(Types.TIMESTAMP))) {
								if (columnType == Types.DATE || columnType == Types.TIME
										|| columnType == Types.TIMESTAMP) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}

							}
						}

					}
				}
			} catch (CubeException e) {
				ApplicationLog.error(e);
			}
		}
		return lovDataList;
	}

	/**
	 * To create cube.
	 * 
	 * @param strCubeName
	 *            cube name
	 * @param sUserName
	 *            user name
	 * @throws CubeException
	 * @throws NotBoundException
	 * @throws IOException
	 */
	public Cube createCube(String strCubeName, UserInfo userInfo, GraphInfo graphInfo)
			throws CubeException, IOException, NotBoundException {

		FileEx cubeFileEx = null;

		if (strCubeName.endsWith(MashUpConstants.DATASETS_FILE_EXT)) {
			cubeFileEx = new FileEx(MashupsConstants.MASHUPS_MODULE_DATASETS, strCubeName);
		} else {
			cubeFileEx = new FileEx(com.elegantjbi.util.AppConstants.CUBES_DIR, strCubeName);
		}
		String strProjectDirectory = cubeFileEx.getCanonicalPath();

		Cube gCube = (Cube) applicationContext.getBean("cubeImpl");
		gCube.setInfoOnResultSet(graphInfo.getCubeInfo(), graphInfo.getGraphName(), AppConstants.GRAPH,
				graphInfo.getGraphId(), graphInfo.isEnableManagedMemory());
		gCube.setUser(userInfo.getUserId());
		gCube.setUserInfo(userInfo);
		gCube.setSkipcubedatasetcolumndataaccesspermission(graphInfo.isSkipcubedatasetcolumndataaccesspermission());
		gCube.setAllowanonymouspublicaccess(graphInfo.isAllowanonymouspublicaccess());
		gCube.setEnablesubcube(graphInfo.isEnablesubcube());
		gCube.setDirectory(strProjectDirectory, graphInfo.getCubeInfo());
		gCube.setAutoRefresh(false);		
		this.cubeDisplayName = graphInfo.getCubeInfo().getDataObjecName();
		this.graphDisplayName = graphInfo.getGraphName();
		
		return gCube;
	}

	@SuppressWarnings("unchecked")
	private boolean setCubeData(GraphInfo graphInfo, String loggedInUserId, boolean createdFromAnalysis)
			throws CubeException, DatabaseOperationException {

		boolean dataSet = false;

		graphInfo.setColColumns(new Vector());
		graphInfo.setRowColumns(new Vector());
		graphInfo.setDataColumns(new Vector());
		graphInfo.setLineGraphRowLabelsForCombinedGraph(new Vector());
		graphInfo.setLineGraphDataLabelsForCombinedGraph(new Vector());
		graphInfo.setDataColLabels3(new Vector());
		graphInfo.setTheDataColLabels4(new Vector());

		// try {
		CubeViewInfo viewInfo = graphCube.getViewStruct(true);
		int theDataColumnCount = viewInfo.getDataColumnInfoList().size();
		int theRowLabelCount = viewInfo.getRowLabelInfoList().size();
		int theColLabelCount = viewInfo.getColLabelInfoList().size();

		Vector<CubeColumnInfo> dataColumnInfoList = new Vector<CubeColumnInfo>();

		CubeColumnInfo theYCubeColumnInfo = null;

		boolean isMapNull = false;
		boolean isFormatNull = false;

		if (getActiveDDVMs(graphInfo, loggedInUserId, false) == null) {
			isMapNull = true;
		}

		Hashtable<String, Vector<Object>> m_dataFormat = null;

		if (graphInfo.getColumnFormat() == null) {
			isFormatNull = true;
			m_dataFormat = new Hashtable<String, Vector<Object>>();
		}

		// Reading all Numerical columns
		for (int theI = 1; theI <= theDataColumnCount; theI++) {
			theYCubeColumnInfo = (CubeColumnInfo) viewInfo.getDataColumnInfoList().elementAt(theI - 1);

			if (theYCubeColumnInfo instanceof CubeDataColumnInfo) {
				continue;
			}

			String theColumnName = theYCubeColumnInfo.toString();

			switch (theYCubeColumnInfo.getType()) {
			case Types.BINARY:
			case Types.VARBINARY:
			case Types.LONGVARBINARY:
				continue;
			}

			graphInfo.getDataColumns().addElement(theColumnName);
			graphInfo.getLineGraphDataLabelsForCombinedGraph().addElement(theColumnName);

			dataColumnInfoList.addElement(theYCubeColumnInfo);
		}

		// Reading all row column name
		for (int theI = 1; theI <= theRowLabelCount; theI++) {
			String rowName = viewInfo.getRowLabelInfoList().elementAt(theI - 1).toString();

			graphInfo.getRowColumns().addElement(rowName);
			graphInfo.getLineGraphRowLabelsForCombinedGraph().addElement(rowName);
		}

		// Reading column column name
		for (int theI = 1; theI <= theColLabelCount; theI++) {
			String colName = viewInfo.getColLabelInfoList().elementAt(theI - 1).toString();

			graphInfo.getColColumns().addElement(colName);
		}

		Hashtable<String, Integer> m_colType = new Hashtable<String, Integer>();

		if (isMapNull || isFormatNull) {
			ICubeResultSetMetaData icubeMetaData = getOriginalResultSetMetaData();
			CubeColumnInfo cubeColumnInfo = null;
			for (int iIndex = 1; iIndex <= icubeMetaData.getColumnCount(); iIndex++) {
				cubeColumnInfo = icubeMetaData.getColumn(iIndex);
				m_colType.put(cubeColumnInfo.getName(), new Integer(cubeColumnInfo.getType()));

				if (isFormatNull) {
					// Column Type
					// 1- Date type column
					// 2- Numeric column
					switch (cubeColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector<Object> dateData = new Vector<Object>();
						dateData.add(new Integer(DATE_FORMAT)); // 0-column type
						dateData.add(new String("")); // 1-Date Format string
						dateData.add(new String("")); // 2-Time Format string

						m_dataFormat.put(cubeColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();
						data.add(new Integer(NUMBER_FORMAT)); // 0-column type
						data.add(new Integer(0)); // 1-Negative value representation
						data.add(new Integer(0)); // 2-Maximum Fraction digit
						data.add(new Boolean(false)); // 3-Is comma formatted
						data.add(new String("")); // 4-Unit String
						data.add(new Boolean(false)); // 5-Is Unit at Suffix
						data.add(new Boolean(false)); // 6-Comma Positioning Style

						m_dataFormat.put(cubeColumnInfo.getName(), data);

						break;
					}
				}
			}
			cubeColumnInfo = null;
			icubeMetaData = null;

			CubeVector userDataColumnInfo = graphCube.getUserColumnInfoList();

			for (int i = 0; i < userDataColumnInfo.size(); i++) {
				UddcTemplateInfo dataLable = (UddcTemplateInfo) userDataColumnInfo.get(i);
				if (dataLable.isVirtual())
					graphInfo.getUserVirtualColumnInfoList().add(dataLable);
			}

			userDataColumnInfo = graphCube.prepareUserColumnInfoList(userDataColumnInfo,
					graphCube.getDataColumnInfoList(), new HashMap(), new HashMap(), new CubeVector(), new HashMap(), new HashMap(),
					null);

			userDataColumnInfo = graphCube.prepareDataColumnInfoList(userDataColumnInfo);

			CubeVector dataInfoVec = new CubeVector();
			dataInfoVec.addAll(dataColumnInfoList);
			dataInfoVec.addAll(userDataColumnInfo);

			graphCube.setDataColumnInfoList(dataInfoVec);
			CubeDataColumnInfo cubeDataColumnInfo = null;

			for (int cnt = 0; cnt < userDataColumnInfo.size(); cnt++) {
				cubeDataColumnInfo = (CubeDataColumnInfo) userDataColumnInfo.get(cnt);

				m_colType.put(cubeDataColumnInfo.getName(), new Integer(cubeDataColumnInfo.getType()));

				if (isFormatNull) {
					// Column Type
					// 1- Date type column
					// 2- Numeric column
					switch (cubeDataColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector<Object> dateData = new Vector<Object>();
						dateData.add(new Integer(DATE_FORMAT)); // 0-column type
						dateData.add(new String("")); // 1-Date Format string
						dateData.add(new String("")); // 2-Time Format string

						m_dataFormat.put(cubeDataColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();
						data.add(new Integer(NUMBER_FORMAT)); // 0-column type
						data.add(new Integer(0)); // 1-Negative value representation
						data.add(new Integer(0)); // 2-Maximum Fraction digit
						data.add(new Boolean(false)); // 3-Is comma formatted
						data.add(new String("")); // 4-Unit String
						data.add(new Boolean(false)); // 5-Is Unit at Suffix
						data.add(new Boolean(false)); // 6-Comma Positioning Style

						m_dataFormat.put(cubeDataColumnInfo.getName(), data);

						break;
					}
				}
			}

			// For duplicate measures
			for (int iCnt = 0; iCnt < dataColumnInfoList.size(); iCnt++) {
				cubeColumnInfo = dataColumnInfoList.elementAt(iCnt);

				if (!cubeColumnInfo.getSourceName().equals(cubeColumnInfo.getName())) {
					Vector<Object> data = new Vector<Object>();
					data.add(new Integer(NUMBER_FORMAT)); // 0-column type
					data.add(new Integer(0)); // 1-Negative value representation
					data.add(new Integer(0)); // 2-Maximum Fraction digit
					data.add(new Boolean(false)); // 3-Is comma formatted
					data.add(new String("")); // 4-Unit String
					data.add(new Boolean(false)); // 5-Is Unit at Suffix
					data.add(new Boolean(false)); // 6-Comma Positioning Style
					m_dataFormat.put(cubeColumnInfo.getName(), data);
				}
			}
			cubeColumnInfo = null;

			graphInfo.setColumnFormat(m_dataFormat);
		}

		graphInfo.setDataColumnInfoList(dataColumnInfoList);

		graphInfo.setColumnType(m_colType);

		if (graphInfo.getObjectCubeDefinition() == null) {
			graphInfo.setObjectCubeDefinition(new ObjectCubeDefinitionInfo());
		}

		graphOrgCube = (Cube) graphCube.Clone();
		graphInfo.setUserLabelInfoList(graphOrgCube.getUserLabelInfoList());

		// Successfully set cube in Drilldown graph
		graphInfo.setGraphVisible(true);

		dataSet = true;

		return dataSet;
	}

	private boolean setCubeData(GraphInfo graphInfo, String loggedInUserId)
			throws DatabaseOperationException, CubeException {
		return setCubeData(graphInfo, loggedInUserId, false);
	}

	public GraphInfo initializeGraph(int graphMode, Hashtable<String, Object> params, UserInfo loggedInUser,
			boolean putLock) throws MDXException, RealTimeCubeException, CubeException, IOException, NotBoundException,
			DatabaseOperationException, ObjectAccessException, ObjectNotFoundException, CubeNotFoundException,
			CubeAccessException, RScriptException, ALSException {

		return initializeGraph(graphMode, params, loggedInUser, null, putLock, null);
	}

	@SuppressWarnings("rawtypes")
	public GraphInfo initializeGraph(int graphMode, Hashtable<String, Object> params, UserInfo loggedInUser, Cube cube,
			boolean putLock, GraphInfo graphInfo) throws MDXException, RealTimeCubeException, CubeException,
			IOException, NotBoundException, DatabaseOperationException, ObjectAccessException, ObjectNotFoundException,
			CubeNotFoundException, CubeAccessException, RScriptException, ALSException {

		boolean requireSetGraph = false;
		IDataObject cubeInfo = null;

		Vector theDataColLabels = null;
		Vector theDataColLabels2 = null;
		Vector theRowColLabels = null;
		Vector theRowColLabels2 = null;
		Vector theColColLabels = null;
		if (graphMode == AppConstants.NEW_MODE) {
			if (params.get("cubeId").toString().endsWith(MashUpConstants.DATASETS_FILE_EXT)) {
				cubeInfo = dataSetsService.getById(params.get("cubeId").toString());
			} else if (params.get("cubeId").toString().endsWith(AppConstants.NLP_FILE_EXT)) {
				cubeInfo = cubeDataServiceUtil.getCubeInfoById(params.get("cubeId").toString());
			} else {
				cubeInfo = cubeDataServiceUtil.getCubeByCubeId(params.get("cubeId").toString());
			}
			if(cubeInfo == null) {
				cubeInfo = cube.getCubeInfo();
			}
			graphInfo = new GraphInfo();
			graphInfo.setGraphMode(AppConstants.NEW_MODE);
			graphInfo.setGraphName(ResourceManager.getString("GRAPH_NEW"));
			graphInfo.setCreatedBy(loggedInUser);
			graphInfo.setCubeInfo(cubeInfo);
			String graphId = String.valueOf(System.currentTimeMillis());
			graphInfo.setNewGraphId(graphId);
			try {
				graphInfo.setPdfPageSetup(pageSetupServiceUtil.getPDFPageSetupInfo());
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_SET_PDFPAGESETUP",
						new Object[] { loggedInUser.getUsername() }), e);
			}
		} else if (graphMode == AppConstants.OPEN_MODE) {
			String graphId = StringUtil.null2String(params.get("objectId"));
			if (graphInfo == null) {
				graphInfo = getGraphById(graphId);
			}
			if(params.get("checkPermission") == null) {
				checkPermissions(graphInfo, AppConstants.GRAPH, loggedInUser);				
			}

			if (putLock) {
				lockObject(graphId, AppConstants.GRAPH_TITLE, loggedInUser.getUserId());
			}
			cubeInfo = graphInfo.getCubeInfo();

			requireSetGraph = true;

			graphInfo.setReadFromCache(true);
		}

		if (cube != null) {
			// For Graph generated from analysis. Cube object will be passed from
			// AnalysisService
			graphCube = cube;
			// Bug #12038
			graphCube.setInfoOnResultSet(graphInfo.getCubeInfo(), graphInfo.getGraphName(), AppConstants.GRAPH,
					graphInfo.getGraphId(), graphInfo.isEnableManagedMemory());
			graphCube.setEnablesubcube(graphInfo.isEnablesubcube());
			// For Solving bug no : 3800 Rank not applied in Graph generated from analysis
			// only
			graphCube.setAutoRefresh(false);
			graphCube.setDataoperationison(graphInfo.getGraphProperties().getApplyDataoperationwhen());
			
		} else {
			graphCube = createCube(cubeInfo.getDataObjectId(), loggedInUser, graphInfo);
			if (graphMode == AppConstants.NEW_MODE) {
				graphCube.setObjectId(graphInfo.getNewGraphId());
				if (cubeInfo.getDatabaseCubeType() == ICubeConstants.R_CUBE
						|| cubeInfo.getDatabaseCubeType() == ICubeConstants.REALTIME_R_CUBE) {
					if (graphCube != null) {
						graphCube.setrProfileId(cubeInfo.getDatabaseId());
						graphCube.setrInputCubeId(cubeInfo.getrInputCubeId());
						graphCube.setrScriptInputVOs(cubeInfo.getrScriptInputVOs());
						graphCube.setrScriptOutputVOs(cubeInfo.getrScriptOutputVOs());
					}
				}
			}
		}

		if (graphInfo.getDataColumns() != null) {
			theDataColLabels = (Vector) graphInfo.getDataColumns().clone();
		}
		if (graphInfo.getRowColumns() != null) {
			theRowColLabels = (Vector) graphInfo.getRowColumns().clone();
		}
		if (graphInfo.getColColumns() != null) {
			theColColLabels = (Vector) graphInfo.getColColumns().clone();
		}
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			theDataColLabels2 = (Vector) graphInfo.getLineGraphDataLabelsForCombinedGraph().clone();
			theRowColLabels2 = (Vector) graphInfo.getLineGraphRowLabelsForCombinedGraph().clone();
		}
		
		CubeVector vUserDefinedDataColumns = getAllUserDefinedColumns(loggedInUser);
		long start = System.currentTimeMillis();
		if(!loggedInUser.isFromAPI()) {
			metadatacolumnvalidation(graphInfo, loggedInUser,vUserDefinedDataColumns);
		}
		ApplicationLog.debug("Total time for validation in Graph name => "+graphInfo.getGraphName()+ " Time == >> "+(System.currentTimeMillis()-start));
		if (requireSetGraph) {
			readObjectCubeDefinition(graphInfo, loggedInUser, cubeInfo);
			Boolean fromPublishProcess = null;
			if (params.containsKey("fromPublishProcess")) {
				fromPublishProcess = (Boolean) params.get("fromPublishProcess");
			}

			if (!cubeColumnPermission && null != fromPublishProcess && !fromPublishProcess) {
				throw new ObjectAccessException("MSG_CHECK_OBJECT_PERMISSION");
			} else if (!cubeColumnPermission && null == fromPublishProcess) {
				throw new ObjectAccessException("MSG_CHECK_OBJECT_PERMISSION");
			}
			graphCube.setShowRankOthers(
					graphInfo.getGraphProperties().getxAxisProperties().getLabelProperties().isOthers());

			initializeActiveFilter(graphInfo,loggedInUser);
		}

		setCubeData(graphInfo, loggedInUser.getUserId());

		if (params.containsKey("windowScreenHeight") && params.containsKey("windowScreenWidth")) {
			graphInfo.setWindowScreenWidth((Integer) (params.get("windowScreenWidth")));
			graphInfo.setWindowScreenHeight((Integer) (params.get("windowScreenHeight")));
		}
		if (params.containsKey("graphAreaFitToSection")) {
			graphInfo.setGraphAreaFitToSection((Boolean) params.get("graphAreaFitToSection"));
		}

		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			if (theRowColLabels.size() > 0 && theRowColLabels2.size() > 0 && theColColLabels.size() == 0) {
				if (theRowColLabels.get(0).equals(theRowColLabels2.get(0)))
					theRowColLabels2.remove(0);
			}
			graphInfo.setColColumns(theColColLabels);
			graphInfo.setRowColumns(theRowColLabels);
			graphInfo.setDataColumns(theDataColLabels);
			graphInfo.setLineGraphRowLabelsForCombinedGraph(theRowColLabels2);
			graphInfo.setLineGraphDataLabelsForCombinedGraph(theDataColLabels2);
		} else {
			if (theColColLabels != null) {
				graphInfo.setColColumns(theColColLabels);
			}
			if (theRowColLabels != null) {
				graphInfo.setRowColumns(theRowColLabels);
			}
			if (theDataColLabels != null) {
				graphInfo.setDataColumns(theDataColLabels);
			}
		}

		// For sort coumn check
		List<CubeLabelInfo> sortList = graphInfo.getActiveTemplateProperties().getSortList();
		if (sortList != null && sortList.size() > 0) {
			for (int i = 0; i < sortList.size(); i++) {
				CubeLabelInfo cubeLabelInfo = sortList.get(i);
				String columnName = cubeLabelInfo.getName();
				if (graphCube.getOriginalResultSetMetaData().findColumn(columnName) == 0) {
					sortList.remove(i);
				}
			}
		}
		GraphProperties gp = graphInfo.getGraphProperties();
		if (gp != null)
			this.setAdaptiveBehaviour("" + gp.getAdaptiveBehaviour());
		verifyUsedDimensionAndMeasures(graphInfo, loggedInUser);
		graphCube.setDateFrequencyMap(graphInfo.getDateFrequencyMap());
		verifyFilterCondition(graphInfo);
		setDataFormatAndMapFromCube(graphInfo, loggedInUser);

		if (graphInfo.getSubCubeMetaDataInfo() != null) {
			// graphInfo.getSubCubeMetaDataInfo().readFromXml();
			graphOrgCube.setSubCubeMetadataList(graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataList());

			if (graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList() != null
					&& graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList().size() > 0) {
				graphOrgCube.setSubCubeMetadataListForDashBoard(
						graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList());
			}
		}

		initializeGraphImage(graphInfo, graphMode);

		boolean requireSetGraphData = false/* = requireSetGraph */; // Commented to avoid repeated retrieval of data
																	// during OPEN_MODE-By Preethi 08/12/2015
		if (params.containsKey("fromPublishNow")) {
			requireSetGraphData = (boolean) params.get("fromPublishNow");
		}
		if (params.containsKey("autoRefresh_dashboard")) {
			boolean bRefresh = ((Boolean) params.get("autoRefresh_dashboard"));
			requireSetGraphData = bRefresh;
			graphInfo.setReadFromCache(bRefresh);
		}
		if (params.containsKey("isFromAPI")) {
			boolean bRefresh = ((Boolean) params.get("isFromAPI"));
			requireSetGraphData = bRefresh;
			graphInfo.setReadFromCache(false);
		}

		doGraphChanged(graphInfo.getGraphType(), requireSetGraphData, graphInfo, loggedInUser);
		if (requireSetGraphData) {
			setDefaultProperties(graphInfo);
		}
		Vector<String> tmpDataItemVector = (Vector<String>) graphInfo.getDataColumns().clone();
		if (tmpDataItemVector == null) {
			tmpDataItemVector = new Vector<>();
		}
		List<String> activeUddcList = new ArrayList<>();
		List<String> dataList = new ArrayList<>();
		List<ActiveUDDCInfo> tActiveUDDCList = graphInfo.getActiveUDDCInfo(loggedInUser.getUserId());
		if (tActiveUDDCList == null) {
			tActiveUDDCList = new ArrayList<>();
		}
		if (!tActiveUDDCList.isEmpty()) {
			for (String mesName : tmpDataItemVector) {
				dataList.add(mesName);
			}
			for (ActiveUDDCInfo uddc : tActiveUDDCList) {
				String mesName = uddc.getUddcTemplateInfo().getColumnName();
				if (!uddc.getUddcTemplateInfo().getBaseuddc().isEmpty())
					mesName = uddc.getUddcTemplateInfo().getBaseuddc();
				activeUddcList.add(mesName);
			}
		}

		if (!activeUddcList.isEmpty()) {
			List<String> rowColDimList = new ArrayList<>(dataList);
			Vector rowDim = graphInfo.getRowColumns();
			rowColDimList.addAll(rowDim);
			Vector colDim = graphInfo.getColColumns();
			rowColDimList.addAll(colDim);
			String[] activeUddcs = activeUddcList.toArray(new String[0]);
			String[] mesRowColDimItems = rowColDimList.toArray(new String[0]);
			checkOutlinerUddcdublicateColumn(new String[] {}, activeUddcs, mesRowColDimItems,
					cubeInfo.getDataObjectId(), cubeInfo, false, loggedInUser, null,
					graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
		}
		graphCubeBar = (Cube) graphCube.Clone();
		graphCubeLine = (Cube) graphCube.Clone();
		return graphInfo;
	}

	/**
	 * Verify condition if column has added in page filter condition and has been
	 * remove while cube rebuilding process from the cube method will remove deleted
	 * column condition and update the filter condition.
	 * 
	 * @param graphInfo
	 */

	private void verifyFilterCondition(GraphInfo graphInfo) {
		CubeInfo cubeInfo = null;
		if (graphInfo.getCubeInfo().getDataObjectType() == ICubeConstants.REALTIME_R_CUBE) {
			try {
				cubeInfo = cubeDataServiceUtil.getCubeByCubeId(graphInfo.getCubeInfo().getrInputCubeId());
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);
			}
		}
		if (graphInfo != null) {
			String[][] filterConditionArray = graphInfo.getMultiPageFilterInfo();

			if (filterConditionArray != null && filterConditionArray.length > 0) {
				List<String[]> tmpList = new ArrayList<String[]>();
				for (String[] strFilterInfoArray : filterConditionArray) {
					if (strFilterInfoArray != null && strFilterInfoArray.length > 0) {
						String columnName = strFilterInfoArray[0];
						try {
							if (graphInfo.getCubeInfo().getDataObjectType() == ICubeConstants.REALTIME_R_CUBE
									&& cubeInfo != null) {
								boolean isColumnExist = cubeInfo.getCubeColumnInfoList().stream()
										.anyMatch(cubeColumnInfo -> cubeColumnInfo.getColumnName().equals(columnName));
								if (isColumnExist) {
									tmpList.add(strFilterInfoArray);
								}
							} else {
								if (graphCube.getOriginalResultSetMetaData().findColumn(columnName) > 0) {
									tmpList.add(strFilterInfoArray);
								} else {
									if (graphCube.getFilterConditions().containsKey(columnName)) {
										graphCube.getFilterConditionsMap().remove(columnName);
										CubeVector conditionsVector = graphInfo.getRayOuterConditions();
										CubeVector tmpCubeVector = new CubeVector();
										if (conditionsVector != null && conditionsVector.size() > 0) {
											for (Object object : conditionsVector) {
												if (object instanceof CubeConditionInfo) {
													CubeConditionInfo cubeConditionInfo = (CubeConditionInfo) object;
													if (!columnName.equals(cubeConditionInfo.getColumnName())) {
														tmpCubeVector.add(cubeConditionInfo);
													}
												}
											}
											graphInfo.setRayOuterConditions(tmpCubeVector);
										}

									}
								}
							}
						} catch (CubeException e) {
							ApplicationLog.error(e);
						}
					}
				}
				int size = tmpList.size();
				if (size > 0) {
					String[][] updatedFilterConditionArray = new String[size][];
					for (int i = 0; i < tmpList.size(); i++) {
						updatedFilterConditionArray[i] = tmpList.get(i);
					}
					graphInfo.setMultiPageFilterInfo(updatedFilterConditionArray);
				} else {
					graphInfo.setMultiPageFilterInfo(null);
				}

				List<String> strColumnList = new ArrayList<String>();
				if (filterConditionArray != null && filterConditionArray.length > 0) {
					for (int i = 0; i < filterConditionArray.length; i++) {
						strColumnList.add(filterConditionArray[i][0]);
					}
				}
				graphOrgCube.setObjectpagefiltercolumnList(strColumnList);
			}
		}
		// For Retrieval Parameters check
		if (graphInfo != null && graphInfo.getActiveTemplateProperties() != null
				&& graphInfo.getActiveTemplateProperties().getPreloadingParameters() != null) {
			ArrayList<ParamItem> preLodedCondition = graphInfo.getActiveTemplateProperties().getPreloadingParameters();
			ArrayList<ParamItem> preLodedCondition1 = new ArrayList<ParamItem>();
			for (ParamItem item : preLodedCondition) {
				try {
					if (graphInfo.getCubeInfo().getDataObjectType() == ICubeConstants.REALTIME_R_CUBE
							&& cubeInfo != null) {
						com.elegantjbi.entity.admin.CubeColumnInfo cubeColInfo = cubeInfo.getDataObjectColumnInfoList()
								.stream()
								.filter(cubeColumnInfo -> cubeColumnInfo.getColumnName().equals(item.getColumnName()))
								.findFirst().orElse(null);
						if (cubeColInfo != null) {
							item.setColumnType(cubeColInfo.getColumnType());
							preLodedCondition1.add(item);
						}
					} else {
						com.elegantjbi.core.olap.CubeColumnInfo cubeColumnInfo = null;
						if (graphCube.getOriginalResultSetMetaData() != null) {
							for (int iIndex = 1; iIndex <= graphCube.getOriginalResultSetMetaData()
									.getColumnCount(); iIndex++) {
								cubeColumnInfo = graphCube.getOriginalResultSetMetaData().getColumn(iIndex);
								if (cubeColumnInfo.getName().equals(item.getColumnName())) {
									break;
								}
								cubeColumnInfo = null;
							}
						}
						if (cubeColumnInfo != null) {
							item.setColumnType(cubeColumnInfo.getType());
							preLodedCondition1.add(item);
						}
					}

				} catch (CubeException e) {
					ApplicationLog.error(e);
				}
			}
			graphInfo.getActiveTemplateProperties().setPreloadingParameters(preLodedCondition1);
			setObjectprelodingparametercolumnList(preLodedCondition1);
		}

	}

	private void initializeGraphImage(GraphInfo graphInfo, int graphMode) {

		setDefaultToolbarGroup(graphInfo);

		resetIndex(graphInfo);

		graphInfo.getDrillDownListOfX().clear();
		graphInfo.getDrillDownListOfZ().clear();
	}

	/**
	 * Sets default flag for toolbar group visibility.
	 */
	private void setDefaultToolbarGroup(GraphInfo graphInfo) {
		setDefaultToolbarGroup(graphInfo.getToolbarButtonGroups());
	}

	/**
	 * Sets default flag for toolbar group visibility of specified Hashtable object.
	 * Is sets default flag when object's status not exists or null.
	 * 
	 * @param bgTable
	 *            Contains Toolbar Button Group Status
	 */
	@SuppressWarnings("unchecked")
	private void setDefaultToolbarGroup(Hashtable bgTable) {

		Boolean tbgStatus = null;

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FILE);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FILE, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FILE_EXPORT);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FILE_EXPORT, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(ALSCommandNameList.CMD_NAME_VIEW_TOOLS);
		if (tbgStatus == null) {
			bgTable.put(ALSCommandNameList.CMD_NAME_VIEW_TOOLS, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_VIEW);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_VIEW, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FORMAT);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FORMAT, Boolean.TRUE);
		}
		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_ZOOM);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_ZOOM, Boolean.TRUE);
		}
	}

	/**
	 * To get graph dimension map.
	 * 
	 * @param cubeInfo
	 *            Cube identifier
	 * @return graph dimension map
	 * @throws CubeException
	 */
	private Hashtable getGraphDimensionMap(IDataObject cubeInfo, UserInfo userInfo, GraphInfo graphInfo)
			throws CubeException {
		ALSColumnMap map;

		try {
			map = new ALSColumnMap(cubeInfo.getDataObjectId(),cubeInfo.getDataObjectDimensionMapInfoList());
			map.setSkipcubedatasetcolumndataaccesspermission(
					graphInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
			return map.getMap(userInfo, cubeInfo);
		} catch (CubeException e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_TO_GET_DIMENSION_MAP",
					new Object[] { cubeInfo, userInfo }), e);

			throw e;
		}
	}

	/**
	 * This method is use to get Graph OutLiner Detail
	 * 
	 * @param outlinerBean
	 *            out liner data object
	 * @param graphInfo
	 *            graph info
	 * @param loggedInUser
	 *            current logged in user detail
	 * @param dimensionList
	 *            cube dimension list
	 * @param strCubeId
	 *            cube id
	 * @param bFromFilter
	 *            flag for filter
	 * @return outliner bean obect
	 * @throws CubeException
	 *             exception
	 * @throws DatabaseOperationException
	 *             exception
	 */
	@SuppressWarnings("unchecked")
	public OutlinerBean getOutlinerData(OutlinerBean outlinerBean, GraphInfo graphInfo, UserInfo loggedInUser,
			List<String> dimensionList, IDataObject cubeInfo, boolean bFromFilter)
			throws CubeException, DatabaseOperationException {

		boolean isPtreeEnable = outlinerBean.isPtreeEnable();
		Hashtable h_dimension_map = outlinerBean.getDimensionMap();
		Vector vcheck_dimension_column = outlinerBean.getCheckDimensionColumn();
		String userId = loggedInUser.getUserId();
		CubeVector vOrderedDataColumns = outlinerBean.getvOrderedDataColumns();
		h_dimension_map = new Hashtable();
		String sCubeName = graphCube.getName();
		// CubeInfo cubeInfo =
		// cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(strCubeId);
		CubeVector srcLabels = outlinerBean.getSrcLabels();
		Vector vKeyLabels = outlinerBean.getvKeyLabels();
		Vector vDataLabels = outlinerBean.getvDataLabels();
		Vector vTimeDimeDataLabel = outlinerBean.getvTimeDimeDataLabel();
		Vector vTimeDimeDataLavel = outlinerBean.getvTimeDimeDataLavel();
		CubeVector vUserDefinedDataColumns = outlinerBean.getvUserDefinedDataColumns();
		CubeVector pageLabels = outlinerBean.getPageLabels();
		CubeVector rowLabels = outlinerBean.getRowLabels();
		CubeVector colLabels = outlinerBean.getColLabels();
		CubeVector dataLabels = outlinerBean.getDataLabels();
		CubeVector vActiveUserDefinedDataColumns = outlinerBean.getvActiveUserDefinedDataColumns();
		Vector<String> itemDisplayName = outlinerBean.getItemDimsplayName();
		List<String> activeGlobalVarNames = new ArrayList<String>();
		CubeColumnExpExecutor expressionExecutor = getColumnExpressionExecutor();
		List<String> virtualUDDC = outlinerBean.getVirtualUDDC();
		try {
			com.elegantjbi.service.analysis.ALSColumnMap map = new com.elegantjbi.service.analysis.ALSColumnMap(
					sCubeName,cubeInfo.getDataObjectDimensionMapInfoList());
			h_dimension_map = map.getMap(loggedInUser, cubeInfo);
			outlinerBean.setDimensionMap(h_dimension_map);
		} catch (Exception e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_GET_DIMENSION_MAP"), e);
		}
		if (!h_dimension_map.isEmpty()) {
			for (Enumeration enumer = h_dimension_map.keys(); enumer.hasMoreElements();) {
				String skey = enumer.nextElement().toString();
				Vector vtemp = (Vector) cubeMetadataServiceUtil.getAllowedColumns(loggedInUser,
						(Vector) h_dimension_map.get(skey), cubeInfo,
						graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));// (Vector)
																								// h_dimension_map.get(skey);

				for (int i = 0; i < vtemp.size(); i++) {
					vcheck_dimension_column.add(vtemp.elementAt(i).toString());
				}
			}

			List<String> tmp = new ArrayList();
			tmp.addAll(h_dimension_map.keySet());
			for (String key : tmp) {
				Vector tmpVector = (Vector) h_dimension_map.get(key);
				if (tmpVector.isEmpty()) {
					h_dimension_map.remove(key);
				}
			}
		}

		if (isPtreeEnable) {
			Vector vecData = cubeMetadataServiceUtil.getDimensionColumnVector(cubeInfo, loggedInUser,
					graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
			vKeyLabels = (Vector) vecData.elementAt(1);
			vDataLabels = (Vector) vecData.elementAt(2);
			vTimeDimeDataLabel = (Vector) vecData.elementAt(3);
			vTimeDimeDataLavel = (Vector) vecData.elementAt(4);
			outlinerBean.setvKeyLabels(vKeyLabels);
			outlinerBean.setvDataLabels(vDataLabels);
			outlinerBean.setvTimeDimeDataLabel(vTimeDimeDataLabel);
			outlinerBean.setvTimeDimeDataLavel(vTimeDimeDataLavel);

			Vector vAllDataList = new Vector();
			vAllDataList.addAll(vDataLabels);
			vAllDataList.addAll(uddcTemplateDAO.getUDDCNameList(sCubeName, userId));
			vAllDataList.addAll(globalVariableDAO.getGloblevariableNameListByCubeId(sCubeName));
			expressionExecutor.setColumnNames(vAllDataList);
		}
		try {
			virtualUDDC = getVirtualUDDCs(loggedInUser.getUserId(), graphInfo);
			vUserDefinedDataColumns = getAllUserDefinedColumns(loggedInUser);

			List<UddcTemplateInfo> uddcTemplateInfoList = new ArrayList<UddcTemplateInfo>();
			for (int i = 0; i < vUserDefinedDataColumns.size(); i++) {
				uddcTemplateInfoList.add((UddcTemplateInfo) vUserDefinedDataColumns.get(i));
			}

			List<ActiveGlobalVariableInfo> activeGolbalVariableList = graphInfo.getActiveTemplateProperties()
					.getActiveGlobalVariableInfo(loggedInUser.getUserId());
			if (activeGolbalVariableList != null && activeGolbalVariableList.size() > 0) {
				for (ActiveGlobalVariableInfo activeGlobalVariableInfo : activeGolbalVariableList) {
					activeGlobalVarNames.add(activeGlobalVariableInfo.getGlobalVariableInfo().getGlobalVariableName());
				}
			}
			// for bug no - 14312
			Vector<String> uddcMeasureList = new Vector<String>(vDataLabels);
			for (UddcTemplateInfo uinfo : uddcTemplateInfoList) {
				uddcMeasureList.add(uinfo.getTemplateName());
			}
			uddcMeasureList.addAll(vKeyLabels);// solving outliner uddc bug(use least/most recent functions).
			uddcMeasureList.addAll(vTimeDimeDataLavel);
			CubeVector validUddcVect = new CubeVector();
			if (vDataLabels.size() > 0) {
				Vector<String> validUddcList = cubeMetadataServiceUtil.getValidUDDCNameList(uddcTemplateInfoList,
						loggedInUser.getUserId(), uddcMeasureList, activeGlobalVarNames, uddcTemplateInfoList);
				validUddcVect.addAll(validUddcList);
			}
			outlinerBean.setvUserDefinedDataColumns(validUddcVect);

			vActiveUserDefinedDataColumns = getUserColumnInfoList();

			List<UddcTemplateInfo> activeUddcInfoList = new ArrayList<UddcTemplateInfo>();
			for (int i = 0; i < vActiveUserDefinedDataColumns.size(); i++) {
				activeUddcInfoList.add((UddcTemplateInfo) vActiveUserDefinedDataColumns.get(i));
			}
			Vector<String> validActiveUddcList = cubeMetadataServiceUtil.getValidUDDCNameList(activeUddcInfoList,
					loggedInUser.getUserId(), uddcMeasureList, activeGlobalVarNames, uddcTemplateInfoList);
			CubeVector validActiveUddcVect = new CubeVector();
			for (int i = 0; i < vActiveUserDefinedDataColumns.size(); i++) {
				UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(i);
				if (validActiveUddcList.contains(uddcTemplateInfo.getTemplateName())) {
					validActiveUddcVect.add(uddcTemplateInfo);
				}
			}

			outlinerBean.setvActiveUserDefinedDataColumns(validActiveUddcVect);
			outlinerBean.setVirtualUDDC(virtualUDDC);
		} catch (Exception e) {
			throw new CubeException(ResourceManager.getString("LOG_ERROR_MSG_FAILED_GETTING_USER_DEFILED_COLUMN_LIST"),
					e);
		}

		// srcLabels = getOrgItemNameList();

		Vector allowSrcColumn = cubeMetadataServiceUtil.getAllowedColumns(loggedInUser, getOrgItemNameList(graphInfo),
				cubeInfo, graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
		if (allowSrcColumn != null) {
			srcLabels.addAll(allowSrcColumn);
		}

		outlinerBean.setSrcLabels(srcLabels);

		for (int i = 0; i < vTimeDimeDataLavel.size(); i++) {
			vKeyLabels.addElement(vTimeDimeDataLavel.elementAt(i));
		}
		outlinerBean.setvKeyLabels(vKeyLabels);
		if (cubeInfo.getDataObjectId() != null) {
			itemDisplayName.addAll(dimensionList);
			Vector activeValidUDDCs = outlinerBean.getActiveValidUDDCs();
			CubeVector displayOrderedDataColumnsName = outlinerBean.getDisplayOrderedDataColumnsName();
			CubeVector rowDisplayLabels = outlinerBean.getRowDisplayLabels();
			CubeVector colDisplayLabels = outlinerBean.getColDisplayLabels();
			CubeVector dataDisplayLabels = outlinerBean.getDataDisplayLabels();
			CubeVector pageDisplayLabels = outlinerBean.getPageDisplayLabels();
			CubeVector colLabelsPrestnt = outlinerBean.getColLabelsPrestnt();
			CubeVector dataLabelsPrestnt = outlinerBean.getDataLabelsPrestnt();
			CubeVector pageLabelsPrestnt = outlinerBean.getPageLabelsPrestnt();
			CubeVector rowLabelsPrestnt = outlinerBean.getRowLabelsPrestnt();

			Vector rowItemsForLineGraph = (Vector) getOutLinerDataWithoutSysGeneratedFields(false, graphInfo)
					.elementAt(3);

			String[] pageItems = outlinerBean.getPageItems();
			String[] rowItems = outlinerBean.getRowItems();
			String[] colItems = outlinerBean.getColItems();
			String[] dataItems = outlinerBean.getDataItems();

			try {

				if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
					int orderedColCnt = graphOrgCube.getColumnCount();
					for (int cntr = 1; cntr <= orderedColCnt; cntr++)
						vOrderedDataColumns.add(graphOrgCube.getColumnName(cntr));
				} else {
					CubeVector orderedDataColList = graphCube.getOrderedDataColumnInfoList();
					List<String> cubeMeasuresList = cubeMetadataServiceUtil.getMeasureList(cubeInfo, loggedInUser,
							false, graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
					Vector vOrderVector = null;
					if (orderedDataColList != null && !orderedDataColList.isEmpty()) {
						for (int i = 0; i < orderedDataColList.size(); i++) {
							if (cubeMeasuresList.contains(orderedDataColList.get(i))) {
								if (vOrderVector == null) {
									vOrderVector = new Vector();
								}
								vOrderVector.add(orderedDataColList.get(i));
							} else if (orderedDataColList.get(i).toString().indexOf('_') != -1) { // for solved bug no -
																									// 14841
								String sourceColNameifDummy = orderedDataColList.get(i).toString().substring(0,
										orderedDataColList.get(i).toString().lastIndexOf('_'));
								if (cubeMeasuresList.contains(sourceColNameifDummy)) {
									if (vOrderVector == null) {
										vOrderVector = new Vector();
									}
									vOrderVector.add(orderedDataColList.get(i));
								}
							}
						}
					}
					
					if(vOrderVector != null) {
						for (int i = 0; i < vOrderVector.size(); i++) {
							String dataColName = vOrderVector.get(i).toString();
							if (graphInfo.getGraphType() != GraphConstants.BUBBLE_GRAPH) {
								Vector colNames = graphInfo.getColColumns();
								if (!colNames.contains(dataColName)) {
									vOrderedDataColumns.add(dataColName);
								}
							} else {
								vOrderedDataColumns.add(dataColName);
							}
						}
					}
					
					if (graphInfo.getGraphType() != GraphConstants.BUBBLE_GRAPH) {
						/*
						 * Vector colNames = graphInfo.getColColumns(); if(!colNames.isEmpty() &&
						 * !vOrderedDataColumns.isEmpty()) { String firstColName =
						 * colNames.get(0).toString(); String dataOrderCol =
						 * vOrderedDataColumns.get(0).toString(); boolean isDimInMeasureInUDDC =
						 * isDimensionInMeasureInUDDC(firstColName, graphInfo,
						 * loggedInUser.getUserId()); if(isDimInMeasureInUDDC &&
						 * !dataOrderCol.equals(firstColName)) { vOrderedDataColumns.add(0,
						 * firstColName); } }
						 */
					} else {
						Vector colNames = graphInfo.getColColumns();
						if (!colNames.isEmpty() && !vOrderedDataColumns.isEmpty()) {
							String firstColName = colNames.get(0).toString();
							String dataOrderCol = vOrderedDataColumns.get(0).toString();
							boolean isDimInMeasureInUDDC = isDimensionInMeasureInUDDC(firstColName, graphInfo,
									loggedInUser);
							if (isDimInMeasureInUDDC && dataOrderCol.equals(firstColName)) {
								vOrderedDataColumns.remove(0);
							}
							if (isDimInMeasureInUDDC && vOrderedDataColumns.contains(firstColName)) {
								vOrderedDataColumns.remove(firstColName);
							}
						}
					}
					// vOrderedDataColumns.addAll(graphCube.getOrderedDataColumnInfoList());
				}

			} catch (Exception e) {
				throw new CubeException(
						ResourceManager.getString("LOG_ERROR_MSG_FAILED_GETTING_ORDERED_DATA_COLUMN_LIST"), e);
			}

			if (pageItems == null) {
				pageLabels = getFilterColumnList(graphInfo, loggedInUser);
				outlinerBean.setPageLabels(pageLabels);
			} else {
				for (int i = 0; i < pageItems.length; i++) {
					if (srcLabels.contains(pageItems[i]))
						pageLabels.addElement(pageItems[i]);
				}
				outlinerBean.setPageLabels(pageLabels);
			}

			if (rowItems == null) {
				if (graphInfo.getSysGeneratedRowLabels().size() > 0) {
					Vector modifiedRowLabels = removeSysGenDimCols(graphInfo.getRowColumns(),
							graphInfo.getSysGeneratedRowLabels());
					rowLabels.addAll(modifiedRowLabels);
				} else {
					rowLabels.addAll(graphInfo.getRowColumns());
				}
				outlinerBean.setRowLabels(rowLabels);
			} else {
				for (int i = 0; i < rowItems.length; i++) {
					if (srcLabels.contains(rowItems[i]))
						rowLabels.addElement(rowItems[i]);
				}
				outlinerBean.setRowLabels(rowLabels);
			}

			if (colItems == null) {

				if (graphInfo.getSysGeneratedColumnLabels().size() > 0) {
					Vector modifiedRowLabels = removeSysGenDimCols(graphInfo.getColColumns(),
							graphInfo.getSysGeneratedColumnLabels());
					colLabels.addAll(modifiedRowLabels);
				} else {
					colLabels.addAll(graphInfo.getColColumns());
				}
				outlinerBean.setColLabels(colLabels);
			} else {
				for (int i = 0; i < colItems.length; i++) {
					if (srcLabels.contains(colItems[i]))
						colLabels.addElement(colItems[i]);
				}
				outlinerBean.setColLabels(colLabels);
			}

			if (!bFromFilter) {
				if (dataItems == null) {
					dataLabels = getOrgDataNameList(graphInfo);
					outlinerBean.setDataLabels(dataLabels);
				} else {
					for (int i = 0; i < dataItems.length; i++) {
						if (srcLabels.contains(dataItems[i]))
							dataLabels.addElement(dataItems[i]);
					}
					outlinerBean.setDataLabels(dataLabels);
				}
			}

			if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
				if (rowItemsForLineGraph == null) {
					rowItemsForLineGraph = new Vector();
				}

				outlinerBean.setRowItemsForLineGraph(rowItemsForLineGraph);

				List<String> rowDisplayLabelsForLine = new ArrayList<String>();

				for (int i = 0; rowItemsForLineGraph != null && i < rowItemsForLineGraph.size(); i++) {
					if (srcLabels.contains(rowItemsForLineGraph.elementAt(i))) {
						rowDisplayLabelsForLine = getAxisDisplayNameCombined(rowItemsForLineGraph, "line", graphInfo);
					}
				}

				outlinerBean.setRowDisplayLabelsForLine(rowDisplayLabelsForLine);

				outlinerBean.setDataItemsForBarGraph(getDataLabelsInSequence(graphInfo));
				outlinerBean.setDataItemsForLineGraph(getCombinedLineDataLabelsInSequence(graphInfo));

				List<String> dataDisplayLabelsInSequenceBar = new ArrayList<String>();
				List<String> dataDisplayLabelsInSequenceLine = new ArrayList<String>();
				dataDisplayLabelsInSequenceBar = getAxisDisplayNameCombined(getDataLabelsInSequence(graphInfo), "bar",
						graphInfo);
				dataDisplayLabelsInSequenceLine = getAxisDisplayNameCombined(
						getCombinedLineDataLabelsInSequence(graphInfo), "line", graphInfo);

				outlinerBean.setDateItemsDispItemsForBarGrf(
						(List<String>) StringUtil.jsEscapeVector(new Vector<String>(dataDisplayLabelsInSequenceBar)));
				outlinerBean.setDateItemsDispItemsForLineGrf(
						(List<String>) StringUtil.jsEscapeVector(new Vector<String>(dataDisplayLabelsInSequenceLine)));
			}

			activeValidUDDCs = outlinerBean.getvActiveUserDefinedDataColumns();
			outlinerBean.setActiveValidUDDCs(activeValidUDDCs);

			// Bug 11684
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					&& (graphInfo.getColMeasureName() != null && graphInfo.getColMeasureName().size() > 0)) {
				if (graphInfo.getColMeasureName().get(0) != null && !graphInfo.getColMeasureName().get(0).equals("")) {
					dataLabels.remove(graphInfo.getColMeasureName().get(0).toString());
					outlinerBean.setDataLabels(dataLabels);
					vOrderedDataColumns.remove(graphInfo.getColMeasureName().get(0).toString());
				}
			}
			// Bug 11684

			if (graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.HISTOGRAM_GRAPH) {
				displayOrderedDataColumnsName.add(getAxisDisplayName(vOrderedDataColumns.get(0).toString(), graphInfo));
			} else if ((graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
					&& graphInfo.getGraphData().isColoumMeasure())
					|| (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
							&& graphInfo.getGraphData().isMeasureInColForBubbLe())) {
				Vector colNames = graphInfo.getColColumns();
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
			} else if ((!graphInfo.getColColumns().isEmpty() && isColMeasureForOutliner
					&& graphInfo.getGraphType() != GraphConstants.SCATTER_LINE_GRAPH)
					|| !graphInfo.getColColumns().isEmpty() && measureInColForBubbLe
							&& graphInfo.getGraphType() != GraphConstants.BUBBLE_GRAPH)// when changing from scatter to
																						// other(col shld be placed in
																						// measure)
			{
				Vector colNames = new Vector(graphInfo.getColColumns());
				vOrderedDataColumns.add(0, colNames.get(0));
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
				if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
					CubeVector orderedDataColList = graphCube.getOrderedDataColumnInfoList();
					if (orderedDataColList.indexOf(colNames.get(0)) != -1)
						colLabels = null;
				} else
					colLabels = null;
			} else {
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
			}
			for (int i = 0; rowLabels != null && i < rowLabels.size(); i++) {
				if (srcLabels.contains(rowLabels.elementAt(i))) {
					rowLabelsPrestnt.add(rowLabels.elementAt(i));
					rowDisplayLabels.add(getAxisDisplayName(rowLabels.elementAt(i).toString(), graphInfo));
				}
			}
			for (int i = 0; pageLabels != null && i < pageLabels.size(); i++) {
				if (srcLabels.contains(pageLabels.elementAt(i))) {
					pageLabelsPrestnt.add(pageLabels.elementAt(i));
					pageDisplayLabels.add(getAxisDisplayName(pageLabels.elementAt(i).toString(), graphInfo));
				}
			}
			for (int i = 0; colLabels != null && i < colLabels.size(); i++) {
				String col = colLabels.elementAt(i).toString();
				if ((graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
						|| graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) && colLabels.size() > 0) {
					for (int ii = 0; ii < vActiveUserDefinedDataColumns.size(); ii++) {
						UddcTemplateInfo uddcInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(ii);
						if (uddcInfo != null && uddcInfo.getColumnName() != null) {
							String uddName = uddcInfo.getColumnName().toString();
							if (uddName.equals(col))
								srcLabels.add(colLabels.elementAt(i));
						}
					}
					/*
					 * if(vActiveUserDefinedDataColumns != null &&
					 * vActiveUserDefinedDataColumns.size()>0 &&
					 * vActiveUserDefinedDataColumns.contains(colLabels.elementAt(i)))
					 * srcLabels.add(colLabels.elementAt(i));
					 */
				}
				if (srcLabels.contains(colLabels.elementAt(i))) {
					colLabelsPrestnt.add(colLabels.elementAt(i));

					colDisplayLabels.add(getAxisDisplayName(colLabels.elementAt(i).toString(), graphInfo));
				}
				if (isColMeasureForOutliner && graphInfo.getGraphType() != GraphConstants.SCATTER_LINE_GRAPH)
					colDisplayLabels = new CubeVector();

				// inactive uddc which is in data, when col has one measure so only one measure
				// remains in col and not in data
				if (colDisplayLabels != null && colDisplayLabels.size() > 0 && dataLabels != null
						&& dataLabels.size() > 0) {
					boolean colUddc = false;
					String colName = colDisplayLabels.get(0).toString();
					String dataName = dataLabels.get(0).toString();
					for (int ii = 0; ii < vActiveUserDefinedDataColumns.size(); ii++) {
						UddcTemplateInfo uddcInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(ii);
						String uddcName = "";
						if (uddcInfo != null && uddcInfo.getColumnName() != null) {
							uddcName = uddcInfo.getColumnName();
							if (uddcName.equals(colName))
								colUddc = true;
						}
					}
					if (colUddc && colName.equals(dataName)) {
						dataLabels = new CubeVector();
						outlinerBean.setDataLabels(dataLabels);
						vOrderedDataColumns.clear();
					}
				}
			}

			// Bug 11684
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					&& (graphInfo.getColMeasureName() != null && graphInfo.getColMeasureName().size() > 0)) {
				if (graphInfo.getColMeasureName().get(0) != null
						&& !graphInfo.getColMeasureName().get(0).toString().equals("")) {
					colLabels.clear();
					colLabels.add(graphInfo.getColMeasureName().get(0).toString());
					outlinerBean.setColLabels(colLabels);
					String name = graphInfo.getColMeasureName().get(0).toString();// COG_1
					String[] originalName = name.split("_");// COG
					colLabelsPrestnt.add(originalName[0]);
					colDisplayLabels
							.add(getAxisDisplayName(graphInfo.getColMeasureName().get(0).toString(), graphInfo));// colDisplayLabels.add(graphInfo.getColMeasureName());
				}
			}
			// Bug 11684

			for (int i = 0; dataLabels != null && i < dataLabels.size(); i++) {
				dataLabelsPrestnt.add(dataLabels.elementAt(i));
				dataDisplayLabels.add(getAxisDisplayName(dataLabels.elementAt(i).toString(), graphInfo));
			}
			for (int i = 0; i < dimensionList.size(); i++) {
				itemDisplayName.add(getAxisDisplayName(dimensionList.get(i), graphInfo));
			}
			HashMap userAddedDataMap = getUserAddedDataNameList(graphInfo);
			HashMap vertualUDDCMap = getVirtualUDDCMap();
			HashMap hsmp = new HashMap();
			hsmp.putAll(userAddedDataMap);
			hsmp.putAll(vertualUDDCMap);

			Iterator iter = hsmp.keySet().iterator();
			String sColName = null;
			Vector<String> duplicateDataColumns = new Vector<String>(vDataLabels.size());
			Vector userAddedMeasures = new Vector<String>(vDataLabels.size());
			while (iter.hasNext()) {
				sColName = iter.next().toString();
				boolean bFound = false;
				int i = 0;
				for (; i < vDataLabels.size(); i++) {
					if (vDataLabels.get(i).equals(sColName)) {
						bFound = true;
						break;
					}
				}

				for (int j = 0; j < graphInfo.getActiveTemplateProperties().getActiveUDDCInfo().size(); j++) {
					if (graphInfo.getActiveTemplateProperties().getActiveUDDCInfo().get(j).getUddcTemplateInfo()
							.getColumnName().equals(sColName)) {
						bFound = true;
						break;
					}
				}

				if (bFound) {
					duplicateDataColumns.add(sColName);
					userAddedMeasures.add((CubeVector) hsmp.get(sColName));
				}
			}
			outlinerBean.setDuplicateDataColumns(duplicateDataColumns);
			outlinerBean.setUserAddedMeasures(userAddedMeasures);
		}
		return outlinerBean;
	}

	/**
	 * This method is use to get VirtualUDDC map key as uddc name and value vector
	 * contain vertual name of uddc.
	 * 
	 * @return HashMap
	 * @throws CubeException
	 */
	@SuppressWarnings("unchecked")
	private HashMap<String, Vector<String>> getVirtualUDDCMap() throws CubeException {
		CubeVector userColumns = getUserColumnInfoList();
		HashMap<String, Vector<String>> hsmp = new HashMap<String, Vector<String>>();
		for (int i = 0; i < userColumns.size(); i++) {
			UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) userColumns.get(i);
			if (uddcTemplateInfo.getBaseuddc().equals(uddcTemplateInfo.getColumnName()) && uddcTemplateInfo.isVirtual())
				continue;
			else if (!uddcTemplateInfo.getBaseuddc().equals(uddcTemplateInfo.getColumnName())
					&& uddcTemplateInfo.isVirtual()) {
				if (hsmp.containsKey(uddcTemplateInfo.getBaseuddc())) {
					((Vector) hsmp.get(uddcTemplateInfo.getBaseuddc())).addElement(uddcTemplateInfo.getColumnName());
				} else {
					Vector vecItemNameList = new CubeVector();
					vecItemNameList.addElement(uddcTemplateInfo.getColumnName());
					hsmp.put(uddcTemplateInfo.getBaseuddc(), vecItemNameList);
				}
			}

		}
		return hsmp;
	}

