	/**
	 * This method searches for measure columns whose source name and name are not
	 * equal. In this sourcename as key and vector of duplicate columns as value.
	 * 
	 * @return User added duplicate measure columns
	 */
	private HashMap getUserAddedDataNameList(GraphInfo graphInfo) {
		CubeVector vecItemNameList = new CubeVector();
		HashMap<String, CubeVector> hsmp = new HashMap<String, CubeVector>();
		CubeColumnInfo columnInfo = null;

		Vector<CubeColumnInfo> dataColumnInfoList = graphInfo.getDataColumnInfoList();

		for (int iCnt = 0; iCnt < dataColumnInfoList.size(); iCnt++) {
			columnInfo = (CubeColumnInfo) dataColumnInfoList.elementAt(iCnt);

			if (!columnInfo.getSourceName().equals(columnInfo.getName())) {
				if (hsmp.containsKey(columnInfo.getSourceName()))
					((CubeVector) hsmp.get(columnInfo.getSourceName())).addElement(columnInfo.getName());
				else {
					vecItemNameList = new CubeVector();
					vecItemNameList.addElement(columnInfo.getName());
					hsmp.put(columnInfo.getSourceName(), vecItemNameList);
				}
			}
		}

		return hsmp;
	}

	/**
	 * Containing all duplicate measure columns.
	 * 
	 * @return Vector containing all duplicate measure columns
	 */
	private Vector getAllUserAddedDataNameList(GraphInfo graphInfo) {
		Vector v = new Vector();
		HashMap<String, CubeVector> hsmp = getUserAddedDataNameList(graphInfo);
		Iterator<String> iter = hsmp.keySet().iterator();
		CubeVector cv = null;

		while (iter.hasNext()) {
			cv = hsmp.get(iter.next());

			for (int i = 0; i < cv.size(); i++) {
				v.addElement(cv.elementAt(i).toString());
			}
		}
		return v;
	}

