	/**
	 * Notification of list changed in OutLiner Dialog.
	 * 
	 * @param in_iNotify
	 *            Total number of notification changed
	 * @param RowLabelInfoList
	 *            the row label information list
	 * @param ColLabelInfoList
	 *            the column label information list
	 * @param DataColumnInfoList
	 *            the data label information list
	 */
	private void changeListNotify(int in_iNotify, CubeVector RowLabelInfoList, CubeVector ColLabelInfoList,
			CubeVector DataColumnInfoList, GraphInfo graphInfo, UserInfo uInfo) {

		try {
			// if column and row Vector are null or contains no element then
			// return
			// to allow user to put only uddcs in rayouter in data column
			if ((RowLabelInfoList == null || RowLabelInfoList.size() < 1)
					&& (ColLabelInfoList == null || ColLabelInfoList.size() < 1)) {
				return;
			}

			graphInfo.getDrillDownListOfX().clear();
			graphInfo.getDrillDownListOfZ().clear();

			Vector theRowColLabels = graphInfo.getRowColumns();
			Vector theColColLabels = graphInfo.getColColumns();
			Vector theDataColLabels = graphInfo.getDataColumns();

			// if data and row Vector are null or contains no element then
			// return
			CubeVector theRowLabelInfoList = new CubeVector();
			CubeVector theColLabelInfoList = new CubeVector();
			CubeVector theDataColumnInfoList = new CubeVector();
			CubeLabelInfo theCubeLabelInfo;

			// Remove all element from Row, Column and Data Vector
			theRowColLabels.removeAllElements();
			theColColLabels.removeAllElements();
			theDataColLabels.removeAllElements();

			// Row Vector
			if (null != RowLabelInfoList) { // Added for SonarQube [21 Apr 2020]
				for (int iCnt = 0; iCnt < RowLabelInfoList.size(); iCnt++) {
					String rowName = (String) RowLabelInfoList.elementAt(iCnt);
					CubeColumnInfo cubeColumnInfo = getColumnMetaData(graphInfo, rowName);
					if (cubeColumnInfo != null) {
						theRowColLabels.addElement(rowName);
						theCubeLabelInfo = new CubeLabelInfo(rowName);
						theCubeLabelInfo.setType(cubeColumnInfo.getType());
						theRowLabelInfoList.addElement(theCubeLabelInfo);
					}
				}
			}

			// Column Vector
			for (int iCnt = 0; iCnt < ColLabelInfoList.size(); iCnt++) {
				String columnName = (String) ColLabelInfoList.elementAt(iCnt);
				CubeColumnInfo cubeColumnInfo = getColumnMetaData(graphInfo, columnName, uInfo.getUserId());
				if (cubeColumnInfo != null) {
					theColColLabels.addElement(columnName);
					theCubeLabelInfo = new CubeLabelInfo(columnName);
					theCubeLabelInfo.setType(cubeColumnInfo.getType());
					theColLabelInfoList.addElement(theCubeLabelInfo);
				}
			}

			// Data Vector
			for (int iCnt = 0; iCnt < DataColumnInfoList.size(); iCnt++) {
				ALSName alsName = (ALSName) DataColumnInfoList.elementAt(iCnt);
				String dataItemName = alsName.GetName();
				CubeColumnInfo cubeColumnInfoClone = getColumnMetaData(graphInfo, dataItemName);

				if (cubeColumnInfoClone != null) {
					cubeColumnInfoClone = (CubeColumnInfo) cubeColumnInfoClone.clone();

					// Duplicate measures
					cubeColumnInfoClone.setSourceName(dataItemName);
					cubeColumnInfoClone.setName(alsName.GetAileas());
					//

					// Duplicate measures
					// theDataColLabels.addElement(theName);
					theDataColLabels.addElement(alsName.GetAileas());
					theDataColumnInfoList.addElement(cubeColumnInfoClone);
				}
			}

			graphInfo.setDataColumnInfoList(theDataColumnInfoList);

			graphOrgCube.setViewStruct(theRowLabelInfoList, theColLabelInfoList, theDataColumnInfoList);

			if (theRowColLabels.size() < 1 && theColColLabels.size() < 1) {
				return;
			}

			// Reseting all index variables
			resetIndex(graphInfo);

			graphInfo.setApplyDefaultRank(false);
			resetErrorMessage(graphInfo);
			resetDrillVector(graphInfo);

			if (graphCube.getAbsoluteColumnCount() > ICubeResultSetUtil.MAX_ABS_COLS) {
				ApplicationLog.info(ResourceManager.getString("MSG_TOOMANY_COLUMN",
						new Object[] { AppConstants.GRAPH, graphInfo.getGraphName(),
								graphInfo.getCubeInfo().getDataObjecName(), graphCube.getAbsoluteColumnCount(),
								"Cube absulute Column count", "GraphService.java" }));
			}
		} catch (Exception e) {
			ApplicationLog.error(e);
		} finally {
		}
	}

	/**
	 * Resets Row, column and Data Vector index.
	 */
	public void resetIndex(GraphInfo graphInfo) {
		graphInfo.setDataIndex(1);
		graphInfo.setRowIndex(1);
		graphInfo.setColIndex(1);
		graphInfo.setSeriesPos(-1);
		graphInfo.setItemPos(-1);

		graphInfo.setDataIndexForLineGraphInCombinedGraph(1);
		graphInfo.setRowIndexForLineGraphInCombinedGraph(1);
	}

	/**
	 * Present cube information is returned.
	 * 
	 * @return CubeViewInfo
	 * @exception CubeException
	 */
	public CubeViewInfo getViewStruct() throws CubeException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		return graphCube.getViewStruct();
	}

	/**
	 * Sets activated template.
	 * 
	 * @param type
	 * @param templates
	 * @param refresh
	 * @exception CubeException
	 * @throws RScriptException
	 */
	public void setCubeActiveTemplates(int type, Object[] templates, boolean refresh)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		graphCube.setActiveTemplates(type, templates, refresh);
	}

	public void setDataItemonViewInfo(CubeViewInfo viewInfo)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {
		graphCube.setViewStruct(viewInfo, false);
	}

	/**
	 * The original cube reconstructed.
	 * 
	 * @exception CubeException
	 * @throws RScriptException
	 */
	public void refresh(GraphInfo graphInfo)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		graphCube.refresh(graphInfo.getCubeInfo());
	}

	/**
	 * To get row,column label sorting information.
	 * 
	 * @return Vector of sorting information
	 */
	public Vector getLabelSortInfo(GraphInfo graphInfo, Vector rowLabels, Vector colLabeList) throws CubeException {

		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}

		Vector vecSortInfoList = new Vector();
		for (int i = 0; i < colLabeList.size(); i++) {
			vecSortInfoList.addElement(graphCube.getSortInfo(AnalysisService.TYPE_COLLABEL, i + 1));
		}

		for (int i = 0; i < rowLabels.size(); i++) {
			vecSortInfoList.addElement(graphCube.getSortInfo(AnalysisService.TYPE_ROWLABEL, i + 1));
		}

		return vecSortInfoList;
	}

	/**
	 * Draw graph with default properties.
	 * 
	 * @param isSetProperty
	 *            set true for default properties otherwise false.
	 * @return true if Graph data set successfully otherwise false.
	 */
	public boolean setGraph(boolean isSetProperty, GraphInfo graphInfo, UserInfo userInfo) {
		try {

			if (graphInfo.getGroupList().size() > 0 && graphInfo.getGraphMode() == AppConstants.OPEN_MODE) {
				setGroupDetail(graphInfo);
			}

			boolean valueSet = setGraphData(graphInfo, userInfo);

			if (!valueSet) {
				applyDDVMList(false, graphInfo, userInfo.getUserId());// Added By Hitesh
				if (isSetProperty) {
					setDefaultProperties(graphInfo);
				}
				return false;
			}
			applyDDVMList(false, graphInfo, userInfo.getUserId());// Added By Hitesh

			if (isSetProperty) {
				setDefaultProperties(graphInfo);
			}

			return true;
		} catch (Exception ex) {
			String strMessage = ResourceManager.getString("MSG_TEXT_GRAPH_DRAWING_FAILED",
					new Object[] { graphInfo.getCubeInfo().getDataObjecName(), AppConstants.GRAPH,
							graphInfo.getGraphName(), "Prepare Graph", ex.getMessage(), "Graph Service" });
			ApplicationLog.error(strMessage, ex);
		}
		return false;
	}

