	private String[] getFilterTemplateNames() throws CubeException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}

		return graphCube.getFilterTemplateNames();
	}

	private int[] getFilterTypes() throws CubeException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}

		return graphCube.getFilterTypes();
	}

	private void setDataOnCubeForDrillDown(GraphInfo graphInfo, int labelType, int labelIndex, int position,
			boolean bMark, CubeVector drillUserLabel, String userId)
			throws CubeException, RScriptException {

		markLabelItem(labelType, labelIndex, position, bMark);
		List<CubeRankDataLabel> rankList = graphInfo.getRankList();
		List<CubeRankDataLabel> activeList = new ArrayList<>();
		for (int cnt = 0; cnt < rankList.size(); cnt++) {
			CubeRankDataLabel rankDaraLabel = rankList.get(cnt);
			if (rankDaraLabel.isStatus()) {
				activeList.add(rankDaraLabel);
			}
		}
		graphCube.setCubeRankDataLabelList(activeList);
		/*
		 * for (int cnt = 0; cnt < rankList.size(); cnt++) { CubeRankDataLabel
		 * rankDataLabel = rankList.get(cnt); if(rankDataLabel.isStatus()) {
		 * if(rankDataLabel.getLabelType() == CubeRankDataLabel.ROW_TYPE) {
		 * setRowRankDataLabel(rankDataLabel); } else { setRankDataLabel(rankDataLabel);
		 * } } }
		 */
		graphCube.setUser(userId);
		long startTime = System.currentTimeMillis();
		setUserLabelInfoList(drillUserLabel);
		long endTime = System.currentTimeMillis();

		CubeVector userSpecificColumns = new CubeVector();
		List<ActiveUDDCInfo> actUDDCInfoList = graphInfo.getActiveUDDCInfo(userId);
		for (ActiveUDDCInfo aInfo : actUDDCInfoList) {
			UddcTemplateInfo uddcInfo = aInfo.getUddcTemplateInfo();
			if (uddcInfo != null) {
				userSpecificColumns.add(uddcInfo);
			}
		}
		setUserColumnInfoList(userSpecificColumns);
		setPackInfoListGraph(graphInfo.getPackConditions());
		Vector<CubeOrderByInfo> sortRowVec = getSortRow(graphInfo);
		Vector<CubeOrderByInfo> sortColVec = getSortCol(graphInfo);
		setSortRow(sortRowVec);
		setSortCol(sortColVec);
	}

	/**
	 * To add active user defined columns in vector.
	 */
	private void addUserColumnsInDataVector(GraphInfo graphInfo, String userId) {
		CubeVector userColumns = new CubeVector();

		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {

			CubeVector uddcList = graphInfo.getUddcInfoListForBarCombinedGraph();

			List<ActiveUDDCInfo> actUDDCInfoList = null;
			if (uddcList != null && uddcList.size() > 0) {
				for (int i = 0; i < uddcList.size(); i++) {

					if (i == 0)
						actUDDCInfoList = graphInfo.getActiveUDDCInfo(userId);

					for (ActiveUDDCInfo aInfo : actUDDCInfoList) {
						UddcTemplateInfo uddcInfo = aInfo.getUddcTemplateInfo();
						if (uddcInfo != null && uddcInfo.getColumnName().equals(uddcList.get(i))) {
							if (!uddcList.contains(uddcInfo))
								userColumns.add(uddcInfo);
						}
					}
				}
			}
			if (userColumns.size() == 0 && (graphInfo.isGraphTypeChanged()
					|| (graphInfo.getGraphName() != null && (graphInfo.getGraphName().equalsIgnoreCase("New tabular"))
							|| graphInfo.getGraphName().equalsIgnoreCase("New crosstab")))
					&& graphInfo.getLineGraphDataLabelsForCombinedGraph().size() == 0
					&& graphInfo.getTheDataColLabels4().size() == 0) {
				userColumns = getActiveUserColumnInfoList(graphInfo, userId);
			}
		} else {
			if ((graphInfo.getTheDataColLabels4().size() == 0 || graphInfo.isGraphTypeChanged()
					|| graphInfo.getUddcInfoListForBarCombinedGraph() != null)
					&& graphInfo.getGraphType() != GraphConstants.COMBINED_GRAPH
					&& graphInfo.getUddcInfoListForLineCombinedGraph() != null
					&& graphInfo.getUddcInfoListForLineCombinedGraph().isEmpty())
				userColumns = getActiveUserColumnInfoList(graphInfo, userId);
		}

		Vector theDataColLabels3 = graphInfo.getDataColLabels3();
		Vector dataColLabelsClone = new Vector(theDataColLabels3);

		if (theDataColLabels3 != null) {
			theDataColLabels3.removeAllElements();
		}

		if (graphInfo.getDataColumns() != null) {
			theDataColLabels3.addAll(graphInfo.getDataColumns());
		}

		int index = -1;

		if (userColumns != null && userColumns.size() > 0) {
			for (int colNo = 0; colNo < userColumns.size(); colNo++) {

				UddcTemplateInfo cbColumn = (UddcTemplateInfo) userColumns.elementAt(colNo);
				if (!theDataColLabels3.contains(cbColumn.toString())) {
					index = GeneralUtil.getOrderedColumnIndex(theDataColLabels3, cbColumn.toString(),
							graphCube.getOrderedDataColumnInfoList(), userColumns);
					theDataColLabels3.insertElementAt(cbColumn.toString(), index);
				}
			}
		}

		if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH && graphInfo.isFromCloseUDDC()
				&& (dataColLabelsClone.size() == theDataColLabels3.size())
				&& (dataColLabelsClone.containsAll(theDataColLabels3)
						&& theDataColLabels3.containsAll(dataColLabelsClone))) {
			graphInfo.setFromCloseUDDC(false);
			theDataColLabels3.removeAllElements();
			theDataColLabels3.addAll(dataColLabelsClone);
		}

		if ((((graphInfo.getGraphType() == GraphConstants.VBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.HBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.STACKED_HBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.STACKED_VBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_HBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_VBAR_GRAPH)
				&& !(graphInfo.getGraphType() == GraphConstants.HISTOGRAM_GRAPH))
				|| graphInfo.getGraphType() == GraphConstants.LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.STACKED_LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.AREA_DEPTH_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.AREA_STACK_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.AREA_PERCENTAGE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.DRILLED_RADAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.DRILLED_STACKED_RADAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PIE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.DOUGHNUT_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.HEAT_MAP_GRAPH)
				&& (!(graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH)) && theDataColLabels3.size() >= 2
				&& !getMultipleYAxisLabelsEnable(graphInfo)) {
			setMultipleYAxisLabelsEnable(true, graphInfo);
		}
		if ((graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH)
				|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.HISTOGRAM_GRAPH)
			setMultipleYAxisLabelsEnable(false, graphInfo);

		// Vector theDataColLabels2temp =
		// graphInfo.getLineGraphDataLabelsForCombinedGraph();
		Vector theDataColLabels2 = graphInfo.getTheDataColLabels4();
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			// Vector theDataColLabels2 =
			// graphInfo.getLineGraphDataLabelsForCombinedGraph();
			if ((theDataColLabels3 != null && theDataColLabels3.size() >= 2)
					|| (theDataColLabels2 != null && theDataColLabels2.size() >= 2)
					|| (graphInfo.getLineGraphDataLabelsForCombinedGraph() != null
							&& graphInfo.getLineGraphDataLabelsForCombinedGraph().size() >= 2)) {
				setMultipleYAxisLabelsEnable(true, graphInfo);
			} else {
				setMultipleYAxisLabelsEnable(false, graphInfo);
			}
		}
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			if (theDataColLabels3 != null && theDataColLabels3.size() <= 1 && theDataColLabels2 != null
					&& theDataColLabels2.size() <= 1 && graphInfo.getLineGraphDataLabelsForCombinedGraph() != null
					&& graphInfo.getLineGraphDataLabelsForCombinedGraph().size() <= 1
					&& getMultipleYAxisLabelsEnable(graphInfo)) {
				setMultipleYAxisLabelsEnable(false, graphInfo);
			}
		} else {
			if (theDataColLabels3 != null && theDataColLabels3.size() <= 1 && getMultipleYAxisLabelsEnable(graphInfo)) {
				setMultipleYAxisLabelsEnable(false, graphInfo);
			}
		}
	}

	/**
	 * To get Active User Defined Columns specified by user name.
	 * 
	 * @param userName
	 *            User Name
	 * @return Active user defined columns
	 */
	private CubeVector getActiveUserColumnInfoList(GraphInfo graphInfo, String userId) {
		CubeVector userSpecificColumns = new CubeVector();
		List<ActiveUDDCInfo> actUDDCInfoList = graphInfo.getActiveUDDCInfo(userId);
		for (ActiveUDDCInfo aInfo : actUDDCInfoList) {
			UddcTemplateInfo uddcInfo = aInfo.getUddcTemplateInfo();
			if (uddcInfo != null) {
				userSpecificColumns.add(uddcInfo);
			}
		}
		return userSpecificColumns;
	}

