	private void setFilterConditions(CubeVector colConditions) throws Exception {
		setFilterConditions(colConditions, false, null);
	}

	private void setFilterConditions(CubeVector colConditions, boolean isRefresh,
			HashMap<String, Object> timeSeriesConditionMap) throws Exception {
		if (graphCube != null) {
			HashMap conditionsMap = new HashMap();

			CubeConditionInfo cubeCondInfo = null;
			String colName = null;
			if (colConditions != null) {
				for (int cntr = 0; cntr < colConditions.size(); cntr++) {
					cubeCondInfo = (CubeConditionInfo) colConditions.get(cntr);
					colName = cubeCondInfo.getColumnName();

					CubeVector cubeVector = (CubeVector) conditionsMap.get(colName);
					if (cubeVector == null) {
						cubeVector = new CubeVector();
						conditionsMap.put(colName, cubeVector);
					}
					cubeVector.add(cubeCondInfo);
				}
			}

			graphCube.setFilterConditions(setConditionGroupId(conditionsMap, timeSeriesConditionMap), false);
		}
	}
	
