	/**
	 * Gets Label position in Cube.
	 * 
	 * @param type
	 *            It should be row or column.
	 * @param colName
	 *            Column Name.
	 * @param labelString
	 *            Label String.
	 * @return Label position in Cube. Returns -1 if label not found or exception
	 *         occurs.
	 * @throws CubeException
	 */
	private int getLabelPosition(int type, String colName, String labelString, GraphInfo graphInfo)
			throws CubeException {
		//return getLabelPosition(graphCube, type, colName, labelString, graphInfo);
		int pos =-1;	
		try {
			pos = getLabelPosition(graphCube, type, colName, labelString, graphInfo);
		}catch(CubeException e) {
			pos =-1;
			ApplicationLog.error("Error in getLabelPosition", e);
		}
		return pos;
	}

	/**
	 * Gets Label position in Cube.
	 * 
	 * @param cube
	 *            Cube Object
	 * @param type
	 *            It should be row or column.
	 * @param colName
	 *            Column Name.
	 * @param labelString
	 *            Label String.
	 * @return Label position in Cube. Returns -1 if label not found or exception
	 *         occurs.
	 * @throws CubeException
	 */
	private int getLabelPosition(Cube cube, int type, String colName, String labelString, GraphInfo graphInfo)
			throws CubeException {

		int pos = -1;
		if (labelString.equals("(NULL)"))// 11870
			labelString = "NULL";
		CubeCondition condition = new CubeCondition(colName, true);
		try {
			int colType = new CubeDAO()
					.getCubeColumnInfoByCubeIdAndColumnName(cube.getCubeInfo().getDataObjectId(), colName)
					.getColumnType();
			if (colType == Types.TIMESTAMP) {
				SimpleDateFormat dateFormat = new SimpleDateFormat("dd-MMM-yyyy");
				Date date = dateFormat.parse(labelString);
				labelString = new SimpleDateFormat("yyyy-MM-dd").format(date);
				labelString += " 00:00:00.0";
			}
		} catch (ParseException e) {
		} catch (DatabaseOperationException e) {
		}

		if (labelString.equals(AppConstants.NULL_DISPLAY_VALUE)) {
			condition.add(null);
		} else {
			condition.add((Object) labelString);
		}

		CubeConditionList conditionList = new CubeConditionList();
		conditionList.add(condition);

		CubeResultSet theResultSet = null;
		/* if (type == Cube.ROW_LABEL) { */
		theResultSet = (CubeResultSet) cube.getDataResultSet();
		/*
		 * } else if (type == Cube.COL_LABEL) { theResultSet = (CubeResultSet)
		 * cube.getLabelResultSet(); }
		 */

		if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH && !theResultSet.search(conditionList)) {
			int iIndex = 0;
			if (labelString.indexOf(".") != -1) {
				labelString = labelString.substring(0, labelString.lastIndexOf("."));
			}
			boolean isNum = StringUtil.isNumber(labelString);
			if (isNum) {
				iIndex = Integer.parseInt(labelString) - 1;
			}
			CubeRecord cashRecord = (CubeRecord) theResultSet.get(iIndex);
			if (cashRecord != null && cashRecord.size() >= 1) {
				int iInd = cashRecord.size() - 1;
				labelString = (String) cashRecord.get(iInd);
				condition = new CubeCondition(colName, true);
				if (labelString.equals(AppConstants.NULL_DISPLAY_VALUE)) {
					condition.add(null);
				} else {
					condition.add((Object) labelString);
				}
				conditionList = new CubeConditionList();
				conditionList.add(condition);
			}
		}

		if (theResultSet != null && theResultSet.search(conditionList)) {
			pos = theResultSet.getPosition();
		}
		conditionList = null;
		return pos;
	}

