	/**
	 * To set data Computation type from specified data Column Information list. For
	 * Example: If user wants data in Sum format,Count format,Average format.
	 * 
	 * @param dataColumnInfoList
	 *            the data column information type
	 * @throws CubeException
	 */
	private void setComputationType(CubeVector dataColumnInfoList, GraphInfo graphInfo) throws CubeException {
		Iterator iterateComputation = graphInfo.getyAxisComputationType().keySet().iterator();

		while (iterateComputation.hasNext()) {
			String columnName = (String) iterateComputation.next();
			int iComputationType = (Integer) graphInfo.getyAxisComputationType().get(columnName);

			int iSetIndex = dataColumnInfoList.indexOf(columnName);
			if (iSetIndex >= 0 && iSetIndex < dataColumnInfoList.size()) {
				CubeColumnInfo cubeColumnInfo = (CubeColumnInfo) dataColumnInfoList.elementAt(iSetIndex);
				cubeColumnInfo.setTotalType(iComputationType);
			} /*
				 * commented code for bug 14340...[Scenario take 2 msr, apply data ops on
				 * one,save,remove one[on which dataOps was applied],save, try to associate[2
				 * msr shown instead of one]] else { CubeDataColumnInfo cubeColumnInfo = new
				 * CubeDataColumnInfo(columnName); cubeColumnInfo.totalType = iComputationType;
				 * dataColumnInfoList.add(cubeColumnInfo); }
				 */
		}
	}

	/**
	 * Initialize graph data.
	 * 
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param params
	 *            contains graph parameter
	 * @param isFromDrillUpProcess
	 *            true if method called for drill up process otherwise false
	 * @return true if first time initialized otherwise false
	 * @throws CubeException
	 * @throws ALSException
	 */
	public boolean initGraphData(GraphInfo graphInfo, Map params, UserInfo userInfo)
			throws CubeException, ALSException {

		long startTime = System.currentTimeMillis();
		String isHomePage = StringUtil.null2String((String) params.get("isHomePage"));
		String isEditObject = StringUtil.null2String((String) params.get("isEditObject"));
		String graph2 = StringUtil.null2String((String) params.get("graph2"));
		String isScoreCard = StringUtil.null2String((String) params.get("isScoreCard"));
		String isFirstTime = StringUtil.null2String((String) params.get("isFirstTime"));
		String zAxisDetail = StringUtil.null2String((String) params.get("zAxisDetail"));
		String isLegend = StringUtil.null2String((String) params.get("isLegend"));
		String position = StringUtil.null2String((String) params.get("position"));
		CubeVector filterCondVect = (CubeVector) params.get("filterCondVect");
		HashMap timeSeriesCondMap = (HashMap) params.get("timeSeriesCondMap");
		String fromExport = StringUtil.null2String((String) params.get("fromExport"));
		boolean firstTime = isFirstTime.equals("true");
		boolean bEditObject = isEditObject.equals("true");
		String isFromDrilDown = StringUtil.null2String((String) params.get("isFromDrillDown"));
		String isDftSetting = StringUtil.null2String((String) params.get("isDefaultSetting"));
		boolean isRefreshReq = Boolean.parseBoolean(StringUtil.null2String((String) params.get("isRefreshReq")));
		// String loggedInUserId =
		// StringUtil.null2String((String)params.get("loggedInUserId"));

		boolean isDefaultSetting = false;
		if (isDftSetting.equals("true")) {
			isDefaultSetting = true;
		}

		setDHTMLGraph(graphInfo, userInfo);
		if (!graphInfo.isRefreshReq()) {
			graphInfo.setRefreshReq(true);
		}
		
		if (this.graphTypeWizard) {
			
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) {
				if ((graphInfo.getGraphData().getRowList() != null || graphInfo.getGraphData().getColList() != null)
						&& (graphInfo.getGraphData().getRowList().size() > 0
								&& graphInfo.getGraphData().getColList().size() > 0)) {
					String dataValueMouseOverFormatText = graphInfo.getGraphProperties().getDataValueProperties()
							.getDataValueMouseOver().getDataValueMouseOverFormatText() + "\n"
							+ GraphCommandNameList.Z_AXIS_TITLE + ": " + GraphCommandNameList.Z_AXIS_VALUE;

					graphInfo.getGraphProperties().getDataValueProperties().getDataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
					graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
					graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
				}

			} else if (graphInfo.getGraphType() != GraphConstants.COMBINED_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.BUBBLE_GRAPH) {
				if ((graphInfo.getGraphData().getRowList() != null
						&& !(graphInfo.getGraphData().getDataLabel().equalsIgnoreCase("Data")))
						&& !(graphInfo.getGraphData().getRowList().isEmpty())) {
					String dataValueMouseOverFormatText = graphInfo.getGraphProperties().getDataValueProperties()
							.getDataValueMouseOver().getDataValueMouseOverFormatText() + "\n"
							+ GraphCommandNameList.Z_AXIS_TITLE + ": " + GraphCommandNameList.Z_AXIS_VALUE;

					graphInfo.getGraphProperties().getDataValueProperties().getDataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
					graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
					graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
				}
			} else {
				if ((graphInfo.getGraphData().getCmbBarrowList() != null
						&& graphInfo.getGraphData().getCmbBardataLabel() != null
						&& !(graphInfo.getGraphData().getCmbBardataLabel().equalsIgnoreCase("Data")))
						&& !(graphInfo.getGraphData().getCmbBarrowList().isEmpty())) {
					String dataValueMouseOverFormatText = graphInfo.getGraphProperties()
							.getCombinedDataValueProperties().getBardataValueMouseOver()
							.getDataValueMouseOverFormatText() + "\n" + GraphCommandNameList.Z_AXIS_TITLE + ": "
							+ GraphCommandNameList.Z_AXIS_VALUE;

					graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
				}
				if ((graphInfo.getGraphData().getCmbLinerowList() != null
						&& graphInfo.getGraphData().getCmbLinedataLabel() != null
						&& !(graphInfo.getGraphData().getCmbLinedataLabel().equalsIgnoreCase("Data")))
						&& !(graphInfo.getGraphData().getCmbLinerowList().isEmpty())) {
					String dataValueMouseOverFormatText = graphInfo.getGraphProperties()
							.getCombinedDataValueProperties().getLinedataValueMouseOver()
							.getDataValueMouseOverFormatText() + "\n" + GraphCommandNameList.Z_AXIS_TITLE + ": "
							+ GraphCommandNameList.Z_AXIS_VALUE;

					graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValueMouseOver()
							.setDataValueMouseOverFormatText(dataValueMouseOverFormatText);
				}
			}
		}

		long endTime = System.currentTimeMillis();
		return firstTime;
	}

