	/**
	 * Gets filter conditions.
	 * 
	 * @return HashMap
	 * @throws CubeException
	 */
	public HashMap getFilterConditions() throws CubeException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		return graphCube.getFilterConditions();
	}

	/**
	 * Gets filter conditions for specified column.
	 * 
	 * @param colName
	 * @return CubeVector
	 * @throws CubeException
	 */
	public CubeVector getFilterConditions(String colName,GraphInfo gInfo) throws CubeException {
		if(gInfo.getGraphType()==GraphConstants.COMBINED_GRAPH) {
			if (graphCubeBar != null && graphCubeLine != null) {				
				CubeVector bar =graphCubeBar.getFilterConditions(colName);
				CubeVector line =graphCubeLine.getFilterConditions(colName);
				if(bar!=null && line!=null && !(bar.equals(line))) {
					return bar.veccat(line);
				}else if(bar!=null) {
					return bar;
				}else if(line!=null) {
					return line;
				}
				return null;
			}else {
				throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
						new Object[] { this.graphDisplayName, this.cubeDisplayName }));
			}			
		}else {
			if (graphCube == null) {
				throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
						new Object[] { this.graphDisplayName, this.cubeDisplayName }));
			}
			return graphCube.getFilterConditions(colName);
		}
		
	}

