	/**
	 * Set Group Detail
	 * 
	 * @param graphInfo
	 *            graph info entity onject
	 * @throws CubeException
	 */
	public void setGroupDetail(GraphInfo graphInfo) throws CubeException {

		List<Group> groupList = graphInfo.getGroupList();
		Vector<String> rowLabels = graphInfo.getRowColumns();
		Vector<String> colLabels = graphInfo.getColColumns();
		CubePackInfoList newPackInfoList = new CubePackInfoList();
		int iType = -1;
		CubeCondition condition = null;
		if (groupList == null || groupList.size() == 0) {
			graphInfo.setPackConditions(new CubePackInfoList());
		}
		for (Group objGroup : groupList) {
			
			condition = new CubeCondition(objGroup.getColumnName(), true);
			condition.setGroupLabel(objGroup.getGroupLabel());
			String groupValues = objGroup.getValues();
			// String selectedValeus[] = StringUtil.tokenize(groupValues, ","); Commented
			// for Group issue Bug #14951 and added below
			String[] selectedValeus = groupValues.split(",");// Added for Group issue Bug #14951 [18 Nov 2018]
			iType = GeneralFiltersUtil.getCubeColumnType(graphInfo.getCubeInfo(), objGroup.getColumnName());
			for (String objValue : selectedValeus) {

				if (iType == Types.INTEGER || iType == Types.SMALLINT || iType == Types.TINYINT) {
					try {
						int labelItemName = Integer.parseInt(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else if (iType == Types.BIGINT || iType == Types.BINARY || iType == Types.VARBINARY
						|| iType == Types.LONGVARBINARY) {
					try {
						long labelItemName = Long.parseLong(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else if (iType == Types.REAL) {
					try {
						float labelItemName = Float.parseFloat(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else if (iType == Types.FLOAT || iType == Types.DOUBLE || iType == Types.DECIMAL
						|| iType == Types.NUMERIC) {
					try {
						double labelItemName = Double.parseDouble(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else if (iType == Types.BIT) {
					try {
						boolean labelItemName = Boolean.parseBoolean(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else if (iType == Types.DATE || iType == Types.TIME || iType == Types.TIMESTAMP) {
					try {
						SimpleDateFormat format = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
						Date labelItemName = format.parse(objValue);
						condition.addElement(labelItemName);
					} catch (Exception ex) {
						condition.addElement(objValue);
					}
				} else {
					String labelItemName = objValue != null ? objValue : (String) null;
					condition.addElement(labelItemName);
				}
			}
			
			if(objGroup.getStatus() == true) {
				newPackInfoList.addElement(condition);
				//graphInfo.setPackConditions(newPackInfoList);
				setDDVMForPackColName(objGroup.getColumnName(), selectedValeus[0], objGroup.getGroupLabel(), graphInfo);
			}else {
				newPackInfoList.removeElement(condition);
				//graphInfo.setPackConditions(newPackInfoList);
				//setDDVMForPackColName(objGroup.getColumnName(), selectedValeus[0], objGroup.getGroupLabel(), graphInfo);
			}
			
		}
		graphInfo.setPackConditions(newPackInfoList);
	}

	/**
	 * This method is used to merge the column in group(pack). It maps Packed Name
	 * with the actual column name.
	 * 
	 * @param colName
	 *            ColName of the value to be packed.
	 * @param actualVal
	 *            Actual Value to be mapped.
	 * @param alternateVal
	 *            Display pack name Value to be mapped
	 * @throws CubeException
	 */
	public void setDDVMForPackColName(String colName, String actualVal, String alternateVal, GraphInfo graphInfo)
			throws CubeException {

		if (graphInfo.getPackDDVMValues() == null) {
			graphInfo.setPackDDVMValues(new HashMap());
		}
		Vector ddvmMappingForCol = (Vector) graphInfo.getPackDDVMValues().get(colName);

		if (ddvmMappingForCol != null && ddvmMappingForCol.size() > 0) {
			setAlreadyPackedValues(colName, actualVal, graphInfo);
		}
		ddvmMappingForCol = (Vector) graphInfo.getPackDDVMValues().get(colName);
		String valMappingArr[] = { actualVal, alternateVal };
		boolean valueFoundInPackDDVM = false;
		if (ddvmMappingForCol == null) {
			ddvmMappingForCol = new Vector();
			ddvmMappingForCol.add(valMappingArr);
		} else {
			for (int i = 0; i < ddvmMappingForCol.size(); i++) {
				String[] conditionValues = (String[]) ddvmMappingForCol.get(i);
				if (conditionValues[0].equals(valMappingArr[0])) {
					ddvmMappingForCol.set(i, valMappingArr);
					valueFoundInPackDDVM = true;
					break;
				}
			}
			if (!valueFoundInPackDDVM) {
				ddvmMappingForCol.add(valMappingArr);
			}
		}
		graphInfo.getPackDDVMValues().put(colName, ddvmMappingForCol);
	}

	/**
	 * This method is used to removes already packed values if new pack is created
	 * from already packed Columns.
	 * 
	 * @param colName
	 *            the column name
	 * @param actualText
	 *            the actual text values
	 * @throws CubeException
	 */
	private void setAlreadyPackedValues(String colName, String actualText, GraphInfo graphInfo) throws CubeException {

		Vector packedValuesVect = (Vector) graphInfo.getPackDDVMValues().get(colName);
		Vector newPackedValues = new Vector();
		Vector indexesToDelete = new Vector();
		for (int i = 0; i < graphInfo.getPackConditions().size(); i++) {

			CubeCondition packCondition = (CubeCondition) graphInfo.getPackConditions().get(i);
			if (packCondition.getColumnName().equalsIgnoreCase(colName)) {
				if (actualText.equalsIgnoreCase(packCondition.get(0).toString())) {
					for (int j = 0; j < packCondition.size(); j++) {
						for (int k = 0; k < packedValuesVect.size(); k++) {
							String[] packedValues = (String[]) packedValuesVect.get(k);

							if (packedValues[0].equalsIgnoreCase(packCondition.get(j).toString())) {
								indexesToDelete.add(new Integer(k));
							}
						}

					}
				}
			}
		}

		for (int i = 0; i < packedValuesVect.size(); i++) {
			if (!indexesToDelete.contains(new Integer(i))) {
				newPackedValues.add(packedValuesVect.get(i));
			}
		}
		graphInfo.getPackDDVMValues().put(colName, newPackedValues);
	}

