	/**
	 * Resets DrillDown vector.
	 */
	public void resetDrillVector(GraphInfo graphInfo) {

		graphInfo.setDrilldownRowPath("");
		graphInfo.setDrilldownColumnPath("");

		if (graphInfo.getDrillRootValues() != null && graphInfo.getDrillRootValues().size() > 0) {
			graphInfo.getDrillRootValues().clear();
		}
		graphInfo.getDrillDownListOfX().clear();
		graphInfo.getDrillDownListOfZ().clear();
		try {
			if (!isFromAnalysis()) {// Added for Bug #15384 [10 Feb 2020]
				clearDrillConditions();
			}
		} catch (CubeException e) {
			ApplicationLog.error(e);
		}
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			resetDrillVectorCombined(graphInfo);
			return;
		}
		if (graphInfo.getDrillVector() != null && graphInfo.getDrillVector().size() >= 1) {
			graphInfo.getDrillVector().removeAllElements();

			clearDrillUpConditions(false, graphInfo);
		}
	}

	/**
	 * Save Graph object.
	 * 
	 * @param graphInfo
	 *            graph info entity object
	 * @param loggedInUser
	 *            Logged in user object
	 * @param objectLockManager
	 *            Object lock manager for current object
	 * @param bSaveAs
	 *            True if saveAs graph otherwise false
	 * @return
	 * @throws DatabaseOperationException
	 * @throws CubeException
	 * @throws RScriptException
	 */
	public GraphInfo saveGraph(GraphInfo graphInfo, UserInfo loggedInUser, boolean bSaveAs)
			throws DatabaseOperationException, MDXException, RealTimeCubeException, CubeException, RScriptException {
		if (bSaveAs) {
			String strDestGraphId = UniqueIdGeneratorUtil.getUniqueDisplayName(AppConstants.GRAPH,
					loggedInUser.getUserId()) + AppConstants.GRAPH_FILE_EXT;
			graphInfo.setGraphId(strDestGraphId);
		}
		setLabelConditionList(new CubeConditionList());
		// checkAndResetDrillUp(graphInfo, true);//for bug 12668
		return updateExistingGraph(graphInfo, loggedInUser, bSaveAs);
	}

	private GraphInfo updateExistingGraph(GraphInfo graphInfo, UserInfo loggedInUser, boolean bSaveAs)
			throws CubeException /* DatabaseOperationException, CubeException */ {

		GraphInfo savedGraphInfo = null;
		HashMap<String, String> params = new HashMap<String, String>();
		FileEx fileObj = null;
		try {
			try {
				boolean isNew = (graphInfo.getGraphMode() == AppConstants.NEW_MODE);
				String message = "";

				if (isNew)
					message = ResourceManager.getString("SAVE_NEW_GRAPH");
				else if (bSaveAs)
					message = ResourceManager.getString("CMD_SAVEAS_GRAPH");
				else
					message = ResourceManager.getString("CMD_SAVE_GRAPH");

			} catch (Exception e) {
				ApplicationLog.error(e);
			}

			if (graphInfo.getGraphMode() == AppConstants.OPEN_MODE) {
				String graphId = graphInfo.getGraphId();
				String graphPhysicalName = graphId.substring(0, graphId.indexOf(AppConstants.GRAPH_FILE_EXT));

				params.put("graphPhysicalName", graphPhysicalName);

			} else if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.setCreatedBy(loggedInUser);
				graphInfo.setCreatedDate(new Date());
			}

			graphInfo.setModifiedBy(loggedInUser);
			graphInfo.setModifiedDate(new Date());

			ObjectCubeDefinitionInfo objectCubeDefinition;

			if (graphInfo.getObjectCubeDefinition() != null) {
				objectCubeDefinition = graphInfo.getObjectCubeDefinition();
			} else {
				objectCubeDefinition = new ObjectCubeDefinitionInfo();
			}

			setObjectCubeDefinition(objectCubeDefinition, graphInfo, loggedInUser.getUsername());
			//graphInfo.setDateFrequencyMap(graphCube.getDateFrequencyMap());
			graphInfo.setObjectCubeDefinition(objectCubeDefinition);

			Vector theRowLabels = new Vector();
			Vector theColLabels = new Vector();
			Vector modifiedRowLabels = new Vector();
			Vector modifiedColLabels = new Vector();
			if (graphInfo.getSysGeneratedRowLabels().size() > 0) {
				modifiedRowLabels = removeSysGenDimCols(graphInfo.getRowColumns(),
						graphInfo.getSysGeneratedRowLabels());
				graphInfo.setRowColumns(modifiedRowLabels);
			} else {
				modifiedRowLabels = graphInfo.getRowColumns();
			}

			if (graphInfo.getSysGeneratedColumnLabels().size() > 0) {
				modifiedColLabels = removeSysGenDimCols(graphInfo.getColColumns(),
						graphInfo.getSysGeneratedColumnLabels());
				graphInfo.setColColumns(modifiedColLabels);
			} else {
				modifiedColLabels = graphInfo.getColColumns();
			}

			if (graphInfo.getSysGeneratedRowLabelsForLineGraph().size() > 0) {
				modifiedRowLabels = removeSysGenDimCols(graphInfo.getLineGraphRowLabelsForCombinedGraph(),
						graphInfo.getSysGeneratedRowLabelsForLineGraph());
				graphInfo.setLineGraphRowLabelsForCombinedGraph(modifiedRowLabels);
			}

			CubeVector colLabelInfoList = new CubeVector();
			CubeVector rowLabelInfoList = new CubeVector();
			int iType = 0;
			for (int i = 0; i < modifiedColLabels.size(); i++) {
				CubeLabelInfo theCubeLabelInfo = new CubeLabelInfo(modifiedColLabels.get(i).toString());
				iType = CubeUtil.getColumnType(modifiedColLabels.get(i).toString(), getOriginalResultSetMetaData(),
						graphInfo.getCubeInfo().getDataObjectId());
				theCubeLabelInfo.setType(iType);
				colLabelInfoList.add(theCubeLabelInfo);
			}

			for (int i = 0; i < modifiedRowLabels.size(); i++) {
				CubeLabelInfo theCubeLabelInfo = new CubeLabelInfo(modifiedRowLabels.get(i).toString());
				iType = CubeUtil.getColumnType(modifiedRowLabels.get(i).toString(), getOriginalResultSetMetaData(),
						graphInfo.getCubeInfo().getDataObjectId());
				theCubeLabelInfo.setType(iType);
				rowLabelInfoList.add(theCubeLabelInfo);
			}

			graphInfo.setColDimensionInfoList(colLabelInfoList);
			graphInfo.setRowDimensionInfoList(rowLabelInfoList);

			// savedGraphInfo is used to get identifier of newly created or updated graph
			// object
			SubCubeMetaDataInfo subCubeMetaDataInfo = subcubedao
					.getSubCubeMetaDataInfoByObjectId(graphInfo.getGraphId());
			if (!graphInfo.getCubeInfo().isRealTimeCube()) {
				// graphInfo.getSubCubeMetaDataInfo().setObjectID(graphInfo.getGraphId());
				if (subCubeMetaDataInfo == null) {
					subCubeMetaDataInfo = new SubCubeMetaDataInfo();
				}
				subCubeMetaDataInfo.setObjectID(graphInfo.getGraphId());
				graphInfo.setSubCubeMetaDataInfo(subCubeMetaDataInfo);
			}

			ArrayList<PageFilterNew> currentFilters = graphInfo.getPageFilterColumnInfo();
			boolean isDashboard = false;
			if(graphInfo.getDashboardInfo()!=null) {
				String dbId = graphInfo.getDashboardInfo().getDashboardId();
				if(dbId != null && !dbId.isEmpty()) {
					ArrayList<PageFilterNew> finalFiltersToSave = saveFiltersForDashboardObject(graphInfo.getPageFilterColumnInfo(), graphInfo.getOriginalPageFilters());
					graphInfo.setPageFilterColumnInfo(finalFiltersToSave);
					graphDAO.updateModifiedDateTime(graphInfo);
					isDashboard = true;
				}
			}
			savedGraphInfo = graphDAO.update(graphInfo);
			
			if(graphInfo.getDashboardInfo()!=null) {
				String dbId = graphInfo.getDashboardInfo().getDashboardId();
				if(dbId != null && !dbId.isEmpty()) {
					graphInfo.setPageFilterColumnInfo(currentFilters);
				}
			}

			graphInfo.setGraphId(savedGraphInfo.getGraphId());
			savedGraphInfo = graphInfo;
			if (!bSaveAs) {
				setUpdateByObjectId(graphInfo.getGraphId(), loggedInUser.getUserId(), true);
			}
			try {
				setDataFormatAndMapFromCube(graphInfo, loggedInUser);
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);
			}
			if(graphInfo.getGraphType()==GraphConstants.COMBINED_GRAPH) {
				graphOrgCube.setObjectId(graphInfo.getGraphId());
			}else {
				graphCube.setObjectId(graphInfo.getGraphId());
			}
			BIDataset<Row> bidataset = SparkUtil.getRealTimeDatasetMap()
					.get(graphInfo.getNewGraphId() + loggedInUser.getUserId());
			if (bidataset != null) {
				SparkUtil.getRealTimeDatasetMap().remove(savedGraphInfo.getNewGraphId() + loggedInUser.getUserId());
				SparkUtil.getRealTimeDatasetMap().put(savedGraphInfo.getGraphId() + loggedInUser.getUserId(),
						bidataset);
			}
			
			
			if(!isDashboard && !bSaveAs) {		
				String graphId = graphInfo.getGraphId();
				String cacheFilePath = "";
				String cacheFilePathLine = "";
				
				if(isobjectCacheOnSingleFile()) {
					cacheFilePath = graphId.substring(0, graphId.indexOf("."));	
				} else {
					cacheFilePath = graphId.substring(0, graphId.indexOf(".")+1)+ loggedInUser.getUserId();
				}
				if(graphInfo.getGraphType()==GraphConstants.COMBINED_GRAPH) {								
					cacheFilePathLine = cacheFilePath+"_line"+ AppConstants.GRAPH_CUBE_DATA_FILE_EXT;
					cacheFilePath = cacheFilePath  + AppConstants.GRAPH_CUBE_DATA_FILE_EXT;
				}
				saveGraphCache(cacheFilePath,graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser),cacheFilePathLine);
			}
			
			if(graphInfo.getGraphType()==GraphConstants.COMBINED_GRAPH) {
				graphOrgCube.setPartitionBy(graphInfo.getPartitionBy());
				graphOrgCube.writeSubeCube(null, false);
			}else {
				graphCube.setPartitionBy(graphInfo.getPartitionBy());
				graphCube.writeSubeCube(null, false);
			}

			/*
			 * graphInfo.getSubCubeMetaDataInfo().setObjectID(graphInfo.getGraphId());
			 * SubCubeMetaDataInfo subCubeMetaDataInfo =
			 * subcubedao.getSubCubeMetaDataInfoByObjectId(graphInfo.getGraphId());
			 * ArrayList<String> getSubCubeMetadataList =
			 * graphCube.getSubCubeMetadataList(); if(subCubeMetaDataInfo != null) {
			 * getSubCubeMetadataList = subCubeMetaDataInfo.getSubCubeMetadataList(); }
			 * graphInfo.getSubCubeMetaDataInfo().setObjectID(graphInfo.getGraphId());
			 * graphInfo.getSubCubeMetaDataInfo().setSubCubeMetadataList(
			 * getSubCubeMetadataList);
			 * 
			 * savedGraphInfo = graphDAO.update(graphInfo);
			 */

			if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.setGraphMode(AppConstants.OPEN_MODE);
			}
		} catch (Exception e) {
			String message = null;
			if (e instanceof DatabaseOperationException) {
				String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
				message = ResourceManager.getString("LOG_ERROR_FAILED_TO_SAVE_GRAPH",
						new Object[] { graphInfo.getGraphName(), graphMode, loggedInUser.getUsername() }) + " "
						+ e.getMessage();
			} else {
				message = ResourceManager.getString("MSG_TEXT_CUBE_EXCEPTION") + " " + e.toString();
			}

			ApplicationLog.error(message, e);
			throw new CubeException(message);
		} finally {
		}

		return savedGraphInfo;
	}

	/**
	 * save chache data for graph in file.
	 * 
	 * @param cacheFilePath
	 * @throws CubeException
	 */
	public void saveGraphCache(String cacheFilePath, boolean isSkipcubedatasetcolumndataaccesspermission,String cacheFilePath2)
			throws CubeException {

		if(cacheFilePath != null && !cacheFilePath.equals("") && cacheFilePath2 != null && !cacheFilePath2.equals("")) {
			FileEx fileObj = FileUtil.getTempFileObject(cacheFilePath);
			graphCubeBar.writeCachedResultSets(fileObj, AppConstants.GRAPH_TITLE,
					isSkipcubedatasetcolumndataaccesspermission);
			
			fileObj = FileUtil.getTempFileObject(cacheFilePath2);
			graphCubeLine.writeCachedResultSets(fileObj, AppConstants.GRAPH_TITLE,
					isSkipcubedatasetcolumndataaccesspermission);
		}else {
			if(cacheFilePath != null && !cacheFilePath.equals("")) {		
			FileEx fileObj = FileUtil.getTempFileObject(cacheFilePath);
			graphCube.writeCachedResultSets(fileObj, AppConstants.GRAPH_TITLE,
					isSkipcubedatasetcolumndataaccesspermission);
			}
		}
	}

	public boolean isobjectCacheOnSingleFile() {
		return graphCube.isobjectCacheOnSingleFile();
	}

	/**
	 * Sets object cube definition properties from the cube for specified object.
	 * 
	 * @param objectCubeDefinition
	 *            Reference of ObjectCubeDefinitionInfo
	 * @throws CubeException
	 */
	private void setObjectCubeDefinition(ObjectCubeDefinitionInfo objectCubeDefinition, GraphInfo graphInfo,
			String userName) throws CubeException {

		try {
			objectCubeDefinition.setViewInfo(graphOrgCube.getCubeViewInfo());
			objectCubeDefinition.setLabelConditions(getLabelConditionList());

			CubePackInfoList packInfoList = graphOrgCube.getPackInfoList();
			for (int j = 0; j < packInfoList.size(); j++) {
				ApplicationLog.debug(" = PackInfoList=== " + packInfoList.elementAt(j));
			}

			objectCubeDefinition.setPackConditions(packInfoList);
			objectCubeDefinition.setDataColumns(graphOrgCube.getDataColumnInfoList());
			objectCubeDefinition.setSuppress(new Integer(graphOrgCube.getSupressZeros()));
			objectCubeDefinition.setDrillConditions(graphOrgCube.getDrillConditions());
			objectCubeDefinition.setDrillColumnsMap(graphOrgCube.getDrillColumnMap());
			objectCubeDefinition.setDrillColumnsSummaryInfoMap(graphOrgCube.getDrillColumnsSummaryInfo());
			objectCubeDefinition.setFilterConditions(graphOrgCube.getObjectFilterConditions());
			objectCubeDefinition.setTimeConditions(graphOrgCube.getTimeSeriesFilters());
			objectCubeDefinition.setLastAppliedObjects(graphOrgCube.getLastAppliedObjs());
			objectCubeDefinition.setOrderedDataColumns(graphCube.getOrderedDataColumnInfoList());
			objectCubeDefinition.setLmRecentSettingsInfo(graphOrgCube.getLMRecentInfo());
			objectCubeDefinition.setRowSummaryOnlyColName(graphOrgCube.getRowSummaryOnlyColName());
			objectCubeDefinition.setColumnSummaryOnlyColName(graphOrgCube.getColSummaryOnlyColName());
			objectCubeDefinition.setDistinctCountMap(graphOrgCube.getDistinctCountMap());

			objectCubeDefinition.setrScriptInputVOs(graphOrgCube.getrScriptInputVOs());
			objectCubeDefinition.setrScriptOutputVOs(graphOrgCube.getrScriptOutputVOs());
			objectCubeDefinition.setrProfileId(graphOrgCube.getrProfileId());
			objectCubeDefinition.setrInputCubeId(graphOrgCube.getrInputCubeId());

		} catch (CubeException e) {
			String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_TO_SET_GRAPH_OBJECT_CUBE_DEFINITION",
					new Object[] { graphInfo.getGraphName(), graphMode, userName }), e);

			throw e;
		}
	}

