	/**
	 * Set Default sorting in graph
	 * 
	 * @throws CubeException
	 *             exception
	 */
	public void setDefaultSorting(GraphInfo graphInfo, UserInfo loggedInUser) {

		Vector vecOrderByInfo = new Vector();
		Vector theRowColLabels = graphInfo.getRowColumns();
		Vector theColColLabels = graphInfo.getColColumns();
		try {
			if (theRowColLabels != null) {
				if (!theRowColLabels.isEmpty()) {
					for (int iCnt = 0; iCnt < graphOrgCube.getViewStruct().getRowLabelInfoList().size(); iCnt++) {
						vecOrderByInfo.addElement(graphOrgCube.getSortInfo(AnalysisService.TYPE_ROWLABEL, iCnt + 1));
					}
				}
				if (!theColColLabels.isEmpty()) {
					for (int iCnt = 0; iCnt < graphOrgCube.getViewStruct().getColLabelInfoList().size(); iCnt++) {
						vecOrderByInfo.addElement(graphOrgCube.getSortInfo(AnalysisService.TYPE_COLLABEL, iCnt + 1));
					}
				}
				List<CubeLabelInfo> cubeOrderByInfos = graphInfo.getSortList();
				for (int i = 0; i < vecOrderByInfo.size(); i++) {
					CubeLabelInfo tmpLabelInfo = (CubeLabelInfo) vecOrderByInfo.get(i);
					tmpLabelInfo.setSortName(tmpLabelInfo.getName() + "_Asc");
					tmpLabelInfo.setCreatedBy(loggedInUser.getUsername());
					tmpLabelInfo.setUpdateBy(loggedInUser.getUsername());
					if (!cubeOrderByInfos.contains(tmpLabelInfo)) {
						tmpLabelInfo.setStatus(true);
						cubeOrderByInfos.add(tmpLabelInfo);
					}
				}
			}
		} catch (CubeException e) {
			ApplicationLog.error(e);
		}
	}

