	/**
	 * Export Graph To PDF
	 * 
	 * @param sout
	 *            OutputStream object
	 * @param graphInfo
	 *            GraphInfo
	 * @throws CubeException
	 *             use for handle Cube Exception
	 * @throws DatabaseOperationException
	 * @throws IOException 
	 */
	public void exportToPDF(OutputStream sout, GraphInfo graphInfo, String userId, boolean isFromScheduler, String exportToken)
			throws CubeException, DatabaseOperationException, IOException {
		String imageFile = PhantomJSUtil.exportPhantomImage(graphInfo.getGraphId(),
				cubeDAO.getById(userId, UserInfo.class), AppConstants.JPG_EXT, 0, 0, getContextURL(), isFromScheduler,exportToken);

		PDFPageSetupInfo pdfPageSetupInfo = graphInfo.getPdfPageSetup();
		ALSPaintImage alsPaint = new ALSPaintImage();

		int topMargin = pdfPageSetupInfo.getPageTopMargin();
		int leftMargin = pdfPageSetupInfo.getPageLeftMargin();
		int bottomMargin = pdfPageSetupInfo.getPageBottomMargin();
		int rightMargin = pdfPageSetupInfo.getPageRightMargin();
		int pageHeight = pdfPageSetupInfo.getPageHeight();
		int pageWidth = pdfPageSetupInfo.getPageWidth();
		alsPaint.setDefaultHeaderFooterProp(pdfPageSetupInfo);
		Hashtable<String, Vector> pdfHeaderFooterProp = alsPaint.getPdfHeaderFooterProp();
		int pdfHeaderHeight = alsPaint.getPdfHeaderHeight();
		int pdfFooterHeight = alsPaint.getPdfFooterHeight();
		Dimension pdfPageSize = new Dimension(pdfPageSetupInfo.getPageWidth(), pdfPageSetupInfo.getPageHeight());
		Insets pageMargins = new Insets(pdfPageSetupInfo.getPageTopMargin(), pdfPageSetupInfo.getPageLeftMargin(),
				pdfPageSetupInfo.getPageBottomMargin(), pdfPageSetupInfo.getPageRightMargin());
		int contentAreaWidth = pageWidth - (leftMargin + rightMargin);
		int ContentAreaHeight = pageHeight - (topMargin + bottomMargin + pdfHeaderHeight + pdfFooterHeight);

		try {
			MediaBox mediaBox = new MediaBox(0, 0, pageWidth, pageHeight);
			PDFGraphics g2 = new PDFGraphics(mediaBox);
			g2.translate(leftMargin, topMargin + pdfHeaderHeight);
			g2.createPage();
			g2.setColor(java.awt.Color.white);
			g2.fillRect(0, 0, pageWidth, pageHeight);
			g2.setColor(java.awt.Color.black);
			alsPaint.paintPDFHeaderFooter(g2, pdfPageSize, pageMargins, pdfHeaderHeight, pdfFooterHeight, userId,
					graphInfo);

			String strErrorMsg = graphInfo.getErrorMessage();
			File phantomImageFile = new File(imageFile);

			Image grfImage = null;
			grfImage = ImageIO.read(phantomImageFile);

			int grfImageWidth = grfImage.getWidth(null);
			int grfImageHeight = grfImage.getHeight(null);

			double widthScale = (contentAreaWidth / (double) grfImageWidth);
			double heightScale = (ContentAreaHeight / (double) grfImageHeight);

			double scaleValue = 1;

			if (widthScale > heightScale)
				scaleValue = heightScale;
			else
				scaleValue = widthScale;

			double newRenderedWidth = scaleValue * grfImageWidth;
			double newRenderedHeight = scaleValue * grfImageHeight;

			g2.setClip(0, 0, contentAreaWidth, ContentAreaHeight);
			g2.drawImage(grfImage, 0, 0, (int) newRenderedWidth, (int) newRenderedHeight, null);
			g2.getPDF().write(sout);
			g2.dispose();
			sout.flush();
			sout.close();
		} catch (Exception e) {

			ApplicationLog.error(e);
		}

	}

	public String getPageFilterSelectedLOV(String columnName, String cubeId)
			throws CubeException, DatabaseOperationException {
		Map<Integer, String[]> filterConditionMap = generateStringFromConditionMap(columnName, cubeId);

		String conditionValue = "";

		if (filterConditionMap != null) {
			for (Entry<Integer, String[]> filterConditionEntry : filterConditionMap.entrySet()) {
				if (filterConditionEntry.getValue()[3].equals(CubeConditionInfo.EQ + "")) {
					if (conditionValue.length() > 0) {
						conditionValue += "|";
					}

					conditionValue += filterConditionEntry.getValue()[2];
				}
			}
		}

		return conditionValue;
	}

