	public GraphData generatePieDoughnutGraphdata(Vector dataVector, GraphData graphData, boolean isTotalVisible,
			int divisionValue, GraphInfo graphInfo, List adjustedDigitList) {
		int dataIndex;
		List dataList = new ArrayList();

		int colIndex;
		List rowList = graphData.getColList();

		int rowIndex;
		List colList = graphData.getRowList();

		Vector header = (Vector) dataVector.elementAt(0);
		dataVector.removeElementAt(0);

		dataIndex = header.indexOf(graphData.getDataLabel());
		colIndex = header.indexOf(graphData.getColLabel());
		rowIndex = header.indexOf(graphData.getRowLabel());

		int colListSize = colList.size();
		int rowListSize = rowList.size();

		if (colListSize == 0) {
			colList.addAll(rowList);
			colListSize = rowListSize;
			colIndex = rowIndex;
			graphData.setColLabel(graphData.getRowLabel());

			rowListSize = 0;
			rowList.clear();
			rowIndex = -1;
			graphData.setRowLabel(null);
		}

		if (rowListSize == 0) {
			rowListSize = 1;
		}

		List dataListForTotal = null;
		if (isTotalVisible) {
			dataListForTotal = new ArrayList();
		}
		// Adjusted Digits
		List tempAdjustedDigitList = new ArrayList();

		/*
		 * for(int i=0;i<adjustedDigitList.size();i++) {
		 * tempAdjustedDigitList.add(adjustedDigitList.get(i)); }
		 */
		// Trend Line
		List trendValue = new ArrayList();
		List trendAlgoList = new ArrayList();
		if (graphInfo.getGraphProperties().getTrendlinePropertiesMap().size() != 0) {

			Map<Integer, TrendLineProperties> testMap = graphInfo.getGraphProperties().getTrendlinePropertiesMap();
			for (Entry<Integer, TrendLineProperties> entry : testMap.entrySet()) {
				String[] splitString = ((String) entry.getValue().getTrendLineColumn()).split(",");
				trendValue.add(splitString[0]);
				trendAlgoList.add(entry.getValue().getTrendLineType().toString());
			}

		}

		Map<String, Double> tempMap = new HashMap<String, Double>();
		/*
		 * int size = dataVector.size(); for (int i = 0; i < size; i++) {
		 * 
		 * Vector record = (Vector) dataVector.elementAt(i); String keyString = "";
		 * if(colIndex != -1){ keyString = record.elementAt(colIndex).toString(); }
		 * if(rowIndex != -1){ keyString+=record.elementAt(rowIndex).toString(); }
		 * if(record.elementAt(dataIndex) != null) {
		 * if(!(record.elementAt(dataIndex).toString().equals("null"))) {
		 * if(!(record.elementAt(dataIndex).toString().equals("0.0")))
		 * tempMap.put(keyString,
		 * Double.parseDouble((record.elementAt(dataIndex).toString()))); } } }
		 */

		int dataVecSize = dataVector.size();
		int recordCount = 0;
		boolean isSwitch = false;
		int zerValueConut = 0;
		Map<String, List> trendMap = new HashMap<String, List>();

		/*
		 * for (int i = 0; i < colListSize; i++) { String colValueFromList =
		 * colList.get(i).toString(); for (int j = 0; j < rowListSize; j++) { String
		 * keyValue = colList.get(i).toString(); if(recordCount >= dataVecSize){
		 * dataList.add(null); continue; }
		 * 
		 * if(rowIndex != -1){ keyValue = rowList.get(j).toString() + keyValue; } Double
		 * dataValue = tempMap.get(keyValue);
		 * 
		 * if(dataValue == null){ dataList.add(null); continue; }
		 * 
		 * if(isTotalVisible){ dataListForTotal.add(dataValue); }
		 * if(tempAdjustedDigitList.size()>0) dataValue = dataValue /
		 * Double.valueOf(tempAdjustedDigitList.get(i).toString()); else dataValue =
		 * dataValue / divisionValue;
		 * 
		 * dataList.add(dataValue); recordCount++; } }
		 * 
		 * if(isTotalVisible){ double total = 0; double dataValue = 0; List totalList =
		 * new ArrayList();
		 * 
		 * for (int j = 0; j < rowListSize; j++) { total = 0; for (int i = 0; i <
		 * colListSize; i++) {
		 * 
		 * int index = i*rowListSize + j; dataValue = (Double)
		 * dataListForTotal.get(index);
		 * 
		 * total += dataValue; } total = total / divisionValue;
		 * 
		 * totalList.add(total); }
		 * 
		 * dataList.addAll(totalList); }
		 */

		graphData.setColList(colList);
		graphData.setRowList(rowList);
		graphData.setDataList(new ArrayList());
		graphData.setTrendMap(trendMap);

		return graphData;
	}

	public void reArrengeDataItems(List<ActiveUDDCInfo> activeUDDCList, GraphInfo graphInfo, UserInfo userInfo) {
		List<String> measureList = null;
		boolean removeUddc = false;
		boolean deactiveUddc = false;
		try {
			measureList = metadataServiceUtil.getMeasureList(graphInfo.getCubeInfo(), userInfo, false,
					graphInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
			CubeVector m_OrderedDataColumnInfoList = graphCube.getOrderedDataColumnInfoList();

			deactiveUddc = true;
			if ((graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) && graphInfo.getColColumns().size() > 0
					&& graphInfo.getColColumns().get(0) != null) {
				CubeVector tempDataList = new CubeVector();
				CubeVector tempUDDClist = new CubeVector();

				for (int j = 0; j < activeUDDCList.size(); j++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(0).getUddcTemplateInfo();
					tempUDDClist.add(uInfo.getTemplateName());
				}
				List<String> uddcList = new ArrayList<String>();
				try {
					uddcList = uddcTemplateDAO.getUDDCNameList(graphCube.getName(), userInfo.getUserId());
				} catch (Exception e) {
					ApplicationLog.error(e);
				}
				for (int i = 0; i < m_OrderedDataColumnInfoList.size(); i++) {
					if (!uddcList.contains(m_OrderedDataColumnInfoList.get(i))) {
						tempDataList.add(m_OrderedDataColumnInfoList.get(i));
					} else {
						if (tempUDDClist.contains(m_OrderedDataColumnInfoList.get(i)))
							tempDataList.add(m_OrderedDataColumnInfoList.get(i));
					}
				}
				for (int i = 0; i < activeUDDCList.size(); i++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(i).getUddcTemplateInfo();
					if (!(m_OrderedDataColumnInfoList.contains(uInfo.getTemplateName()))) {
						m_OrderedDataColumnInfoList.add(uInfo.getTemplateName());
					}
				}
				if (activeUDDCList != null && activeUDDCList.size() == 0) {
					m_OrderedDataColumnInfoList.removeAllElements();
					m_OrderedDataColumnInfoList.addAll(tempDataList);
				}
			} else {
				m_OrderedDataColumnInfoList.removeAllElements();
				for (int k = 0; k < graphInfo.getDataColumnInfoList().size(); k++) {
					m_OrderedDataColumnInfoList.add(graphInfo.getDataColumnInfoList().get(k).getName());

				}

				for (int i = 0; i < activeUDDCList.size(); i++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(i).getUddcTemplateInfo();
					if (!(m_OrderedDataColumnInfoList.contains(uInfo.getColumnName()))) // Changed from
																						// getTemplateName() to
																						// getColumnName() to fix Bug
																						// 15506 Client: Impresario)
					{
						m_OrderedDataColumnInfoList.add(uInfo.getColumnName());// Changed from getTemplateName() to
																				// getColumnName() to fix Bug 15506
																				// (Client: Impresario)
					}
				}
			}

		} catch (DatabaseOperationException e) {
			ApplicationLog.error(e);
		}

	}

	public void addRemoveDataValuesPropertiesFromMap(GraphInfo graphInfo, String userId,
			CubeVector orderedDataColumnInfoList) {
		Map<String, TrendDataValueProperties> dataValuePropertiesMap = graphInfo.getGraphProperties()
				.getDataValuePropertiesMap();
		Map<String, TrendDataValueProperties> finDataValuePropertyMap = new LinkedHashMap<String, TrendDataValueProperties>();
		if (null != orderedDataColumnInfoList) {
			for (int i = 0; i < orderedDataColumnInfoList.size(); i++) {
				String colName = (String) orderedDataColumnInfoList.get(i);
				generateDataValuePropertyMap(i, colName, graphInfo, dataValuePropertiesMap, finDataValuePropertyMap);
			}
		}
		if (orderedDataColumnInfoList != null && orderedDataColumnInfoList.size() == 0) {
			graphInfo.getGraphProperties().setDataValuePropertiesMap(dataValuePropertiesMap);
		} else {
			graphInfo.getGraphProperties().setDataValuePropertiesMap(finDataValuePropertyMap);
		}

	}

	public void generateDataValuePropertyMap(int seq, String seqColumnName, GraphInfo graphInfo,
			Map<String, TrendDataValueProperties> dataValuePropertiesMapOld,
			Map<String, TrendDataValueProperties> finDataValuePropertyMapNew) {
		int adjustedDigits = -1;
		if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
			adjustedDigits = GraphsUtil.getAutoAdjustDigit(GraphsUtil.getMeasureColumnVectorList(graphInfo, 0));
			if (adjustedDigits == 8)
				adjustedDigits = 6;
		}
		if (null != dataValuePropertiesMapOld && !dataValuePropertiesMapOld.isEmpty()
				&& null != dataValuePropertiesMapOld.get("M" + seq)) {
			TrendDataValueProperties yAxisTrendProperty1 = dataValuePropertiesMapOld.get("M" + seq);
			if (seq < graphInfo.getDataColLabels3().size()) {

				Map<String, Object> avaerageMap = graphInfo.getMeasureColAvgMap();
				Double actualValue = (Double) avaerageMap.get(graphInfo.getDataColLabels3().get(seq));
				// setDefaultAdjustedDigitFromValue(graphInfo.getGraphProperties(),
				// actualValue);
				Vector vec = new Vector<>();
				vec.add(actualValue);
				if (dataValuePropertiesMapOld.get("M" + seq).getNumberFormat().isAutovalue()) {
					//adjustedDigits = GraphsUtil.getAutoAdjustDigit(vec);
					if(dataValuePropertiesMapOld.get("M" + seq).getNumberFormat().getCommaFormat()==1) {
						adjustedDigits = GraphsUtil.getAutoAdjustDigitUSFormat(vec);	
					}
					else {
						adjustedDigits = GraphsUtil.getAutoAdjustDigitIndianFormat(vec);
					}
					
					yAxisTrendProperty1.getNumberFormat().setAdjustedDigit(adjustedDigits);

					finDataValuePropertyMapNew.put("M" + seq, yAxisTrendProperty1);

				}
			}
		}
		boolean flag = false;
		for (int j = 0; j < dataValuePropertiesMapOld.size(); j++) {
			TrendDataValueProperties dataValueProperty = dataValuePropertiesMapOld.get("M" + j);
			if (dataValueProperty.getTabMesureName().equals(seqColumnName)) {
				flag = true;
				if (null != graphInfo.getGraphProperties().getColLabelsMap()) {
					if (graphInfo.getGraphProperties().getColLabelsMap().containsKey(seqColumnName)) {
						String displayColName = graphInfo.getGraphProperties().getColLabelsMap().get(seqColumnName);
						dataValueProperty.setTabDisplayColumnName(displayColName);
					}
				}
				finDataValuePropertyMapNew.put("M" + seq, dataValueProperty);
				break;
			}
		}
		boolean emptyRow = null != graphInfo.getRowColumns() && (graphInfo.getRowColumns().isEmpty() || graphInfo.getRowColumns().get(0).equals(""));//
		boolean emptyCol = null != graphInfo.getColColumns() && (graphInfo.getColColumns().isEmpty() || graphInfo.getColColumns().get(0).equals(""));

		if (emptyRow && emptyCol && graphInfo.getGraphType() == GraphConstants.PIE_GRAPH) {
			flag = false;
		}
		if (!flag) {
			TrendDataValueProperties dataValueProperty = new TrendDataValueProperties(false);

			if (adjustedDigits != -1 && seq == 0)
				dataValueProperty.getNumberFormat().setAdjustedDigit(adjustedDigits);
			
			if (adjustedDigits != -1) {

				Map<String, Object> avaerageMap1 = graphInfo.getMeasureColAvgMap();

				Double actualValue = (Double) avaerageMap1.get(graphInfo.getDataColLabels3().get(seq));

				Vector vec = new Vector<>();
				vec.add(actualValue);
				if(dataValueProperty.getNumberFormat().getCommaFormat()==1) {
					adjustedDigits = GraphsUtil.getAutoAdjustDigitUSFormat(vec);	
				}
				else {
					adjustedDigits = GraphsUtil.getAutoAdjustDigitIndianFormat(vec);
				}
				dataValueProperty.getNumberFormat().setAutovalue(true);
				dataValueProperty.getNumberFormat().setAdjustedDigit(adjustedDigits);
				// dataValueProperty.setAutoValue(true);

			}
			if (seq != 0) { // set a defult property for other measures yaxis
				// dataValueProperty.getLineProperties().setVisible(false);
				// dataValueProperty.getLineProperties().getAxisMajorLineTickTrendProperties().setVisible(false);
				// dataValueProperty.getyAxisTitleTrendProperties().setVisible(false);
				// dataValueProperty.getLabelProperties().setVisible(false);
				dataValueProperty.getDataValuePoint().setDataPointLineVisible(false);
			}
			dataValueProperty.setDataValueMouseOver(
					graphInfo.getGraphProperties().getDataValueProperties().getDataValueMouseOver());
			dataValueProperty
					.setDataValuePoint(graphInfo.getGraphProperties().getDataValueProperties().getDataValuePoint());
			String displayColName = seqColumnName;
			if (null != graphInfo.getGraphProperties().getColLabelsMap()) {
				if (graphInfo.getGraphProperties().getColLabelsMap().containsKey(seqColumnName)) {
					displayColName = graphInfo.getGraphProperties().getColLabelsMap().get(seqColumnName);
				}
			}
			dataValueProperty.setTabDisplayColumnName(displayColName);
			dataValueProperty.setTabMesureName(seqColumnName);
			finDataValuePropertyMapNew.put("M" + seq, dataValueProperty);
		}
		if (seq == 0) {
			graphInfo.getGraphProperties().setDataValueProperties(finDataValuePropertyMapNew.get("M0"));
		}
	}

	public void addRemoveYAxisPropertiesFromMap(GraphInfo graphInfo, UserInfo userInfo,
			CubeVector orderedDataColumnInfoList) {
		Map<String, YaxisTrendProperties> yaxisMap = graphInfo.getGraphProperties().getyAxisPropertiesMap();
		Map<String, YaxisTrendProperties> finYAxisPropertyMap = new LinkedHashMap<String, YaxisTrendProperties>();
		List<Integer> colList = new ArrayList<Integer>();
		if (null != orderedDataColumnInfoList) {
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH) { // for xyscatter and bubble
				int index = -1;
				int considerYAxis = -1;
				boolean isDimentionInMeasureInUDDC = false;
				if (null != graphInfo.getColColumns() && graphInfo.getColColumns().size() > 0) { // outliner columns
																									// section has value
					String dimName = graphInfo.getColColumns().get(0).toString();
					isDimentionInMeasureInUDDC = isDimensionInMeasureInUDDC(dimName, graphInfo, userInfo);
					if (isDimentionInMeasureInUDDC) { // column section has first element is measure or uddc
						index = 0;
						considerYAxis = 1;
					} else { // column section first element is not measur and uddc
						considerYAxis = 0;
						index = 0;
					}
				} else { // outliner column section is blank
					if (orderedDataColumnInfoList.size() == 1) { // measure section has only one element
						index = 0;
						considerYAxis = 0;
					} else if (orderedDataColumnInfoList.size() > 1) { // measure section has more than one element
						index = 0;
						considerYAxis = 1;
					}
				}
				String colName = "";
				// for UDDC
				/* when we have uddc in col for XY and disable it */
				if (isDimentionInMeasureInUDDC && considerYAxis < orderedDataColumnInfoList.size())
					colName = orderedDataColumnInfoList.get(considerYAxis).toString();
				else
					colName = orderedDataColumnInfoList.get(0).toString();
				generateYAxisPropertyMap(index, colName, graphInfo, yaxisMap, finYAxisPropertyMap);
			} else { // rest of xyscatter and bubble
				for (int i = 0; i < orderedDataColumnInfoList.size(); i++) {
					String colName = (String) orderedDataColumnInfoList.get(i);
					generateYAxisPropertyMap(i, colName, graphInfo, yaxisMap, finYAxisPropertyMap);
				}
			}
		}
		if (orderedDataColumnInfoList != null && orderedDataColumnInfoList.size() == 0) {
			graphInfo.getGraphProperties().setyAxisPropertiesMap(yaxisMap);
		} else {
			graphInfo.getGraphProperties().setyAxisPropertiesMap(finYAxisPropertyMap);
		}
	}

