	/**
	 * Function to export graph data as XLS and XLSX added on 8 Jan 2020 (Client:
	 * Gufic)
	 * 
	 * @param xlsxSheet
	 * @param outStream
	 * @param graphInfo
	 * @param extension
	 * @param userInfo
	 */
	public void exportXLS(IExcelWriter xlsxSheet, OutputStream outStream, GraphInfo graphInfo, String extension,
			UserInfo userInfo, String exportToken) {
		int pageWidth = 1036;
		int pageHeight = 617;
		Dimension pageDim = new Dimension(pageWidth, pageHeight);
		ArrayList posArray = new ArrayList();
		IExcelWriter wSheet = null;

		try {
			if (xlsxSheet == null) {
				// showObjectInfo =
				// dashboardInfo.getDashBoardProp().getDashBoardGeneralProperites().isShowObjectInfo();
				if (extension.equals(".xlsx")) {
					wSheet = new XLSXWriter(outStream);
				} else {
					wSheet = new XLSWriter(outStream);
				}

				// wSheet.createSheet("Sheet 1", 0);
			} else {
				// showObjectInfo = dashboardInfo.isShowObjectInfo();
				wSheet = xlsxSheet;
			}
			if(graphInfo.getGraphType()==GraphConstants.COMBINED_GRAPH) {
				getFormatedDataListCombine(graphInfo, userInfo);
			}else {
				getFormatedDataList(graphInfo, userInfo);// Added to fill Graph data
			}
			ExportXlsUtil.exportComponentXLS(wSheet, pageDim, graphInfo, userInfo/* , showObjectInfo */);
			if (xlsxSheet == null) {
				wSheet.writeExcel();
			}

		} catch (Exception e) {
			ApplicationLog.error(e);
		}
	}
