	public String getJSONFromService(ConcurrentHashMap inputMap) {
		
		JSONArray json_arr = new JSONArray();
		ConcurrentHashMap<String, String> newInputMap = new ConcurrentHashMap<String, String>();
		List newInputList = new ArrayList<>();
		try {
			Iterator iterat = inputMap.entrySet().iterator();
			while (iterat.hasNext()) {
				Entry thisEntry = (Entry) iterat.next();
				String key = thisEntry.getKey().toString();
				String value = thisEntry.getValue().toString();
				newInputMap.put("label", value);
				newInputMap.put("value", key);
				json_arr.put(newInputMap);
			}
		} catch (Exception e) {
			ApplicationLog.error(e);
		}
		return json_arr.toString();
	}

