	public List<Integer> getColorInfoList(Vector packDisplayList, List tmpList, List<Group> groupList,
			List<SelectItem> legendDataList, List<Integer> colorInfoIndex) {
		/*START [bug-SDEVAPR20-1013]*/
		/*if(tmpList != null && tmpList.size() > 1) {
			List tmpList2 = new ArrayList(tmpList);
			List tmpList3 = new ArrayList(legendDataList);
			for(Object legendDataName : legendDataList) {
				if(!tmpList2.contains(legendDataName)) {
					//tmpList3.add(legendDataName);
					tmpList2.add(legendDataName);
				}
			}
			legendDataList.clear();
			legendDataList.addAll(tmpList);
			legendDataList.addAll(tmpList3);
		}*/
		/*END [bug-SDEVAPR20-1013]*/
		String ddvmActualValue = "";
		List tmpListclone = new ArrayList();
		tmpListclone.addAll(tmpList);

		if (packDisplayList != null && packDisplayList.size() > 0) {
			for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
				String[] values = (String[]) iterator.next();
				for (int i = 0; i < tmpListclone.size(); i++) {
					if (values[1].equalsIgnoreCase(tmpListclone.get(i).toString())) {
						tmpListclone.set(i, values[0]);
					}

				}

			}

			for (int i = 0; i < tmpListclone.size(); i++) {
				String key = tmpListclone.get(i).toString();
				if (key.equalsIgnoreCase("Others")) {
					colorInfoIndex.add(legendDataList.size() + 1);
				}
				else if (key.equalsIgnoreCase("Other")) {
					colorInfoIndex.add(legendDataList.size() + 1);
				}else {
					int found = legendDataList.indexOf(tmpListclone.get(i));
					if(found == -1) {
						found = StringUtil.containsString(key, legendDataList);
					}
					// int found = StringUtil.containsString(key, legendDataList);
					if (found > -1)
						colorInfoIndex.add(found);
					else
						colorInfoIndex.add(i);
				}

			}
		} else {
			long loopStart = System.currentTimeMillis();
			if (legendDataList.equals(tmpListclone)) {
				for (int i = 0; i < tmpListclone.size(); i++) {
					colorInfoIndex.add(i);
				}
			} else {
				for (int i = 0; i < tmpListclone.size(); i++) {
					String key = tmpListclone.get(i).toString();
					if (key.equalsIgnoreCase("Other")) {
						colorInfoIndex.add(legendDataList.size() + 1);
					} 
					else if (key.equalsIgnoreCase("Others")) {
						colorInfoIndex.add(legendDataList.size() + 1);
					}else {
						int found = legendDataList.indexOf(tmpListclone.get(i));
						// int found = StringUtil.containsString(key, legendDataList);
						if(found == -1) {
							found = StringUtil.containsString(key, legendDataList);
						}
						if (found > -1)
							colorInfoIndex.add(found);
						else
							colorInfoIndex.add(i);
					}
				}
			}
		}

		return colorInfoIndex;
	}

