	public String generateD3DataProvider(GraphInfo graphInfo, UserInfo userInfo) {
		String d3ScatterJson = "";
		try {
			if (getRowCount() == 0)
				return d3ScatterJson;
		} catch (CubeException e) {
			ApplicationLog.error(e);
		}
		generateLegendColorInfoList(graphInfo, userInfo);

		ObjectMapper objectMapper = new ObjectMapper();
		List<Map<String, Object>> dpList = generateDataProviderGraph(graphInfo, 0, -1, 0, -1);

		try {
			if (dpList.size() != 0)
				d3ScatterJson = objectMapper.writeValueAsString(dpList);
			
			//ApplicationLog.info(""+d3ScatterJson);
		} catch (JsonGenerationException e) {
			ApplicationLog.error(e);
		} catch (JsonMappingException e) {
			ApplicationLog.error(e);
		} catch (IOException e) {
			ApplicationLog.error(e);
		}
		return d3ScatterJson;
	}

