	protected String getFormatedObject(Object in_objValue, com.elegantjbi.vo.properties.NumberFormat numberFormat,
			boolean isCommaSeparate) {
		String strData = "";

		if (in_objValue == null) {
			return null;
		}

		if (in_objValue instanceof Number) {
			double dValue = ((Number) in_objValue).doubleValue();

			int place = numberFormat.getAdjustedDigit();
			if (place > 0) {
				dValue /= Math.pow(10, place);
			}

			Object commaSepObj = numberFormat.isCommaSeprator();
			boolean commaSep = false;
			if (isCommaSeparate && commaSepObj != null) {
				commaSep = ((Boolean) commaSepObj).booleanValue();
			}

			int commaPosStyleObj = numberFormat.getCommaFormat();
			boolean commaPosStyle = false;
			if (commaPosStyleObj == 2) {
				commaPosStyle = true;
			}

			if (commaSep && commaPosStyle && (dValue <= -100000 || dValue >= 100000)) {
				numberFormat.setCommaSeprator(false);
				String strFmt = GetDecimalFormatString(numberFormat);
				numberFormat.setCommaSeprator(true);
				java.text.DecimalFormat DecFormat = new java.text.DecimalFormat(strFmt);
				strData = DecFormat.format(dValue);
				strData = StringUtil.modifyDataForIndianStyleCommaPos(strData, null, false);
			} else {
				String strFmt = "#####0";
				if (isCommaSeparate)
					strFmt = GetDecimalFormatString(numberFormat);
				java.text.DecimalFormat DecFormat = new java.text.DecimalFormat(strFmt);
				// Check The Infinate & NaN
				if (Double.isInfinite(dValue) || Double.isNaN(dValue)) {
					strData = "";
				} else {
					strData = DecFormat.format(dValue);
				}
			}
			if (numberFormat.isShowadAdjustedSuffixed()) {
				strData += GeneralUtil.getAdjustedDigitSuffix(place);
			}
		}
		return strData;
	}

	public void setMobileDefaultView(GraphInfo graphInfo) {

		boolean showDataValue = true;
		boolean showAxisTitle = true;
		boolean showLegend = true;
		int fontSize = 11;
		if (graphInfo != null) {
			/* String title = dashInfo.getT */
			// Data value
			if (graphInfo.getGraphType() == GraphConstants.PIE_GRAPH) {
				if (graphInfo.getGraphProperties().getPieGraph().isClustered()) {
					showDataValue = false;
				}
				graphInfo.getGraphProperties().getPieGraph().getBorderProperties().setVisible(true);
				graphInfo.getGraphProperties().getPieGraph().getBorderProperties().setAllBorderColor("#ffffff");
				graphInfo.getGraphProperties().getPieGraph().getBorderProperties().setAllBorderWidth(1);
				graphInfo.getGraphProperties().getPieGraph().getBorderProperties().setAllBorderStyle("solid");
				for (int i = 0; i < graphInfo.getGraphProperties().getDataValuePropertiesMap().size(); i++) {
					graphInfo.getGraphProperties().getDataValuePropertiesMap().get("M" + i).getDataValuePoint()
							.setDataValuePointVisible(showDataValue);
					graphInfo.getGraphProperties().getDataValuePropertiesMap().get("M" + i).getDataValuePoint()
							.setPosition("OutSide");
					graphInfo.getGraphProperties().getDataValuePropertiesMap().get("M" + i).getDataValuePoint()
							.getFontProperties().setFontSize(fontSize);
					graphInfo.getGraphProperties().getDataValuePropertiesMap().get("M" + i).getDataValuePoint()
							.setDataPointLineVisible(true);
				}
			} else if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValuePoint()
						.setDataValuePointVisible(showDataValue);
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValuePoint()
						.setPosition("Center");
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValuePoint()
						.getFontProperties().setFontSize(fontSize);
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getBardataValueMouseOver()
						.getDataValueMouseOverBorder().setVisible(false);

				graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValuePoint()
						.setDataValuePointVisible(showDataValue);
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValuePoint()
						.setPosition("Top");
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValuePoint()
						.getFontProperties().setFontSize(fontSize);
				graphInfo.getGraphProperties().getCombinedDataValueProperties().getLinedataValueMouseOver()
						.getDataValueMouseOverBorder().setVisible(false);
			} else {

				/*graphInfo.getGraphProperties().getDataValueProperties().getDataValuePoint()
						.setDataValuePointVisible(showDataValue);*/
				graphInfo.getGraphProperties().getDataValueProperties().getDataValuePoint()
				.setDataValuePointVisible(graphInfo.getGraphProperties().getDataValueProperties().getDataValuePoint().isDataValuePointVisible());
				graphInfo.getGraphProperties().getDataValueProperties().getDataValuePoint().getFontProperties()
						.setFontSize(fontSize);
				graphInfo.getGraphProperties().getDataValueProperties().getDataValueMouseOver()
						.getDataValueMouseOverBorder().setVisible(false);
			}
			// title
			if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
				graphInfo.getGraphProperties().getCombinedYaxisProperties().getBarYaxisProperties()
						.getyAxisTitleTrendProperties().setVisible(showAxisTitle);
				graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
						.getyAxisTitleTrendProperties().setVisible(showAxisTitle);

				graphInfo.getGraphProperties().getCombinedYaxisProperties().getBarYaxisProperties()
						.getyAxisTitleTrendProperties().getFontProperties().setFontSize(fontSize);
				graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
						.getyAxisTitleTrendProperties().getFontProperties().setFontSize(fontSize);
			} else {
				int ySize = graphInfo.getGraphProperties().getyAxisPropertiesMap().size();
				for (int i = 0; i < ySize; i++) {
					graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + i).getyAxisTitleTrendProperties()
							.setVisible(showAxisTitle);
					graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + i).getyAxisTitleTrendProperties()
							.getFontProperties().setFontSize(fontSize);
				}
				graphInfo.getGraphProperties().getyAxisProperties().getyAxisTitleTrendProperties()
						.setVisible(showAxisTitle);
				graphInfo.getGraphProperties().getyAxisProperties().getyAxisTitleTrendProperties().getFontProperties()
						.setFontSize(fontSize);
			}
			// Legend
			graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties().setLegendPanelVisible(true);
			graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties().setDrillDown(true);
		}
	}

	public String GetDecimalFormatString(com.elegantjbi.vo.properties.NumberFormat numberFormat) {
		String strFormat = "";
		Object key_coma = null;

		key_coma = numberFormat.isCommaSeprator();

		if (key_coma != null) {
			boolean bValue = ((Boolean) key_coma).booleanValue();
			if (bValue) {
				strFormat += "###,##0";
			} else {
				strFormat += "#####0";
			}
		}
		Object obj = null;

		obj = numberFormat.getNumberOfDigits();

		int scale = 0;
		if (obj != null) {
			scale = ((Integer) obj).intValue();
		}
		for (int i = 0; i < scale; i++) {
			if (i == 0) {
				strFormat += '.';
			}
			strFormat += '0';
		}
		strFormat += ';';
		int iChoice = 0;

		iChoice = numberFormat.getNegativeNumberFormat();

		switch (iChoice) {
		case 0:
			strFormat += '-';
			break;
		case 1:
			strFormat += " ";
			break;
		case 2:
			strFormat += '(';
			break;
		case 3:
			strFormat += ResourceManager.getString("DOLLAR");
			break;
		case 4:
			strFormat += ResourceManager.getString("EURO");
			break;
		}

		obj = key_coma;
		if (obj != null) {
			boolean bValue = ((Boolean) obj).booleanValue();
			if (bValue) {
				strFormat += "###,##0";
			} else {
				strFormat += "#####0";
			}
		}
		for (int i = 0; i < scale; i++) {
			if (i == 0) {
				strFormat += '.';
			}
			strFormat += '0';
		}

		switch (iChoice) {
		case 2:
			strFormat += ')';
			break;
		}

		return strFormat;
	}

