	public String getValueFromColumnLabel(String label, GraphInfo graphInfo) {
		if (graphInfo.getGraphProperties().getColLabelsMap() != null && graphInfo.getGraphProperties().getColLabelsMap().size() != 0) {
			for(String s : graphInfo.getGraphProperties().getColLabelsMap().keySet()) {
				if(graphInfo.getGraphProperties().getColLabelsMap().get(s).equalsIgnoreCase(label)) {
					return s;
				}
			}
		}
		return label;
	}
	

