public boolean retrievalonloadcheck(GraphInfo graphInfo, UserInfo userInfo) {
	boolean isRetrievalonload = true;
	try {
		ArrayList<String> lstStr = new ArrayList();
		if(graphInfo.getActiveTemplateProperties().getPreloadingParameters() != null) {
			if(graphInfo.getCubeInfo() != null) {
				String[] columnNames = GeneralFiltersUtil.getColumnNamesWithMeasure(cubeMetadataServiceUtil, graphInfo.getCubeInfo(), userInfo);
				if(columnNames != null && columnNames.length > 0) {
					List slt = Arrays.asList(columnNames);
					for(ParamItem item:graphInfo.getActiveTemplateProperties().getPreloadingParameters()) {
						if(slt.contains(item.getColumnName())) {
							lstStr.add(item.getColumnName());
						}
					}
				}
			}
		}
		if(lstStr.isEmpty()) {
			 isRetrievalonload = false;
		}
	} catch (Exception e) {
		ApplicationLog.error(e);
	}
	return isRetrievalonload;
}

	private Thread getSubCube(GraphInfo graphInfo, CubeVector theRowLabelInfoList, CubeVector theColLabelInfoList,
			CubeVector theDataColumnInfoList, boolean bCache, FileEx cacheDataFilePath,boolean isBar, UserInfo userInfo,
			HashMap filterColumnConditionMapClone,	HashMap filterUpdateColumnConditionMapClone) {
		return new Thread(() -> {					          
		    	try {
		    		/*CurrentTenantIdentifierResolverImpl.setTenantIds(CurrentTenantIdentifierResolverImpl.getCurrentTenantIdentifier());
		    		Cube threadCube = (Cube) graphOrgCube.Clone();  // Assuming a clone method exists
		    		setAciveUddcforCombine(graphInfo, isBar, userInfo, threadCube);*/
		    		
		    		if(isBar) {		
		    			graphOrgCube.setFilterColumnConditionMap(filterColumnConditionMapClone);
						graphOrgCube.setFilterUpdateColumnConditionMap(filterUpdateColumnConditionMapClone);
		    			detailedMonitorEndpoint.setProcessLog(Thread.currentThread().getId(),graphInfo.getGraphName(),graphInfo.getGraphId(),"Get bar chart data for combine","Refresh data",Thread.currentThread(),userInfo,new Date());
		    			graphCubeBar = graphOrgCube.getSubCube(theColLabelInfoList, theRowLabelInfoList,
		    					deepCloneMeasure(theDataColumnInfoList), /* getConditionVect() */graphInfo.getOutlinerFilter(), true,
							true, false, bCache, cacheDataFilePath, false, true,false, "true");
		    		}else {	
		    			graphOrgCube.setFilterColumnConditionMap(filterColumnConditionMapClone);
						graphOrgCube.setFilterUpdateColumnConditionMap(filterUpdateColumnConditionMapClone);
		    			detailedMonitorEndpoint.setProcessLog(Thread.currentThread().getId(),graphInfo.getGraphName(),graphInfo.getGraphId(),"Get line chart data for combine","Refresh data",Thread.currentThread(),userInfo,new Date());
		    			graphCubeLine = graphOrgCube.getSubCube(theColLabelInfoList, theRowLabelInfoList,
		    					deepCloneMeasure(theDataColumnInfoList), /* getConditionVect() */graphInfo.getOutlinerFilter(), true,
								true, false, bCache, cacheDataFilePath, false, true,false, "false");
		    		}
				} catch (CubeException | RScriptException e) {
					ApplicationLog.error(e);
				} finally {
					detailedMonitorEndpoint.removeActiveRequest(Thread.currentThread().getId());
				}
		});
		
	}
	public void setAciveUddcforCombine(GraphInfo graphInfo,boolean isBar, UserInfo userInfo, Cube barCube) throws CubeException, RScriptException {
		
		if (barCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		 List<ActiveUDDCInfo> actUDDCInfoList = graphInfo.getActiveUDDCInfo(userInfo.getUserId());

	        
	        List<UddcTemplateInfo> list = actUDDCInfoList.stream()
	                .map(ActiveUDDCInfo::getUddcTemplateInfo)
	                .collect(Collectors.toList());

	        if (isBar && graphInfo.getUddcInfoListForBarCombinedGraph() != null) {
	            List<String> barCombinedGraphList = graphInfo.getUddcInfoListForBarCombinedGraph();
	            list.removeIf(uddcTemplateInfo -> !barCombinedGraphList.contains(uddcTemplateInfo.getTemplateName()));
	        } else if (graphInfo.getUddcInfoListForLineCombinedGraph() != null) {
	        	List<String> lineCombinedGraphList = graphInfo.getUddcInfoListForLineCombinedGraph();
	            list.removeIf(uddcTemplateInfo -> !lineCombinedGraphList.contains(uddcTemplateInfo.getTemplateName()));
	        }
	        Object[] activeTemplateIds = list.toArray(new Object[0]);
	       /* graphOrgCube.getCubeforGraph(String.valueOf(isBar)).setActiveTemplates(TemplateUtil.ANA_USER_UDDC, activeTemplateIds, false);*/	
	        barCube.setActiveTemplates(TemplateUtil.ANA_USER_UDDC, activeTemplateIds, false);		
	}
	
	public void removeTimeCondition(HashMap columnConditions, String conditionKey, HashMap timeConditions) {
		CubeVector conditionVector = (CubeVector) columnConditions.get(conditionKey);

		if (conditionVector != null && !conditionVector.isEmpty()) {
			for (int i = 0; i < conditionVector.size(); i++) {
				Object conditionObj = conditionVector.get(i);

				if (conditionObj instanceof CubeConditionInfo) {
					try {
						if (getOriginalResultSetMetaData().findColumn(
								((CubeConditionInfo) conditionObj).getColumnName()) == 0)
							conditionVector.remove(i--);
					} catch (CubeException e) {
						ApplicationLog.error("Error in timecondition : ",e);
					}
				}
			}

			if (conditionVector.isEmpty())
				timeConditions.remove(conditionKey);
		}
	}
	
	
