	public void clearDistictLMRecentMap(GraphInfo graphInfo, CubeVector orderedDataItems) {
		
		 try {
			if ((graphInfo.getObjectCubeDefinition().getDistinctCountMap() != null || 
					graphInfo.getObjectCubeDefinition().getLmRecentSettingsInfo() != null)
					&& orderedDataItems != null) {				
			   		    
			    Set<String> orderedDataItemsSet = new HashSet<>();
			    for (int i = 0; i < orderedDataItems.size(); i++) {
			        orderedDataItemsSet.add(orderedDataItems.elementAt(i).toString());
			    }
	
			    if (graphInfo.getObjectCubeDefinition().getDistinctCountMap() != null) {
				    Iterator<String> iterator = graphInfo.getObjectCubeDefinition().getDistinctCountMap().keySet().iterator();
				    while (iterator.hasNext()) {
				        String key = iterator.next();
				        if (!orderedDataItemsSet.contains(key)) {
				            iterator.remove(); 
				        }
				    }	
				    setDistinctCountMap(graphInfo.getObjectCubeDefinition().getDistinctCountMap());
				    setDistinctOperationMap(graphInfo.getObjectCubeDefinition().getDistinctCountOperationMap());
				}
			    
				if (graphInfo.getObjectCubeDefinition().getLmRecentSettingsInfo() != null) {
					Iterator<String> iterator = graphInfo.getObjectCubeDefinition().getLmRecentSettingsInfo().keySet().iterator();
				    while (iterator.hasNext()) {
				        String key = iterator.next();
				        if (!orderedDataItemsSet.contains(key)) {
				            iterator.remove(); 
				        }
				    }
				    setLMRecentInfo(graphInfo.getObjectCubeDefinition().getLmRecentSettingsInfo());	
				}
			}else {
				  graphInfo.getObjectCubeDefinition().setDistinctCountMap(new HashMap<>());
				  graphInfo.getObjectCubeDefinition().setDistinctCountOperationMap(new HashMap<>());
				  graphInfo.getObjectCubeDefinition().setLmRecentSettingsInfo(new HashMap<>());
				  setDistinctCountMap(graphInfo.getObjectCubeDefinition().getDistinctCountMap());
				  setDistinctOperationMap(graphInfo.getObjectCubeDefinition().getDistinctCountOperationMap());
				  setLMRecentInfo(graphInfo.getObjectCubeDefinition().getLmRecentSettingsInfo());
			}
			
		}catch (Exception e) {
			ApplicationLog.error(e);		
		}
	}
	
