	private CubeVector deepCloneMeasure(CubeVector original) {
		CubeVector clone = new CubeVector();
		HashSet<String> seen = new HashSet<>();

		for (int i = 0; i < original.size(); i++) {
			Object obj = original.get(i);

			String key = null;
			Object clonedObj = obj;

			if (obj instanceof CubeDataColumnInfo) {
				CubeDataColumnInfo dataCol = (CubeDataColumnInfo) obj;
				clonedObj = dataCol.clone();
				key = dataCol.getName();//dataCol.getSourceName(); 
			} else if (obj instanceof CubeColumnInfo) {
				CubeColumnInfo col = (CubeColumnInfo) obj;
				clonedObj = col.clone();
				key = col.getName();//col.getSourceName(); 
			} else if (obj instanceof CubeColumnDataInfo) {
				CubeColumnInfo col = (CubeColumnDataInfo) obj;
				clonedObj = col.clone();
				key = key = col.getName();//col.getSourceName(); 
			} else {
				key = obj.toString();
			}
			if (!seen.contains(key)) {
				seen.add(key);
				clone.add(clonedObj);
			}
		}
		return clone;
	}

	
